        <div className="absolute right-0 bottom-full mb-2 w-32 bg-card border border-border rounded-xl shadow-2xl p-1.5 z-20">
          {options.map((option) => (
            <button
              key={option}
              onClick={() => {
                onChange(option);
                setOpen(false);
              }}
              className={cn(
                'w-full text-left px-2 py-1.5 rounded-md text-xs hover:bg-muted transition capitalize',
