/* ── Custom Markdown & Inline Style Renderer ───────────────────────── */

export function parseSequentialText(text: string): { type: 'thinking' | 'finalOutput'; content: string }[] {
  const blocks: { type: 'thinking' | 'finalOutput'; content: string }[] = [];
  let currentIndex = 0;

  const markers = [
    { open: '<thinking>', close: '</thinking>' },
    { open: '<think>', close: '</think>' },
    { open: '[THINK]', close: '[/THINK]' },
    { open: '[REASONING]', close: '[/REASONING]' }
  ];

  while (currentIndex < text.length) {
    let earliestOpenIdx = -1;
    let selectedMarker = null;

    for (const marker of markers) {
      const idx = text.indexOf(marker.open, currentIndex);
      if (idx !== -1 && (earliestOpenIdx === -1 || idx < earliestOpenIdx)) {
        earliestOpenIdx = idx;
        selectedMarker = marker;
      }
    }

    if (earliestOpenIdx === -1) {
      const remaining = text.slice(currentIndex);
      if (remaining) {
        blocks.push({ type: 'finalOutput', content: remaining });
      }
      break;
    }

    if (earliestOpenIdx > currentIndex) {
      const preceding = text.slice(currentIndex, earliestOpenIdx);
      if (preceding) {
        blocks.push({ type: 'finalOutput', content: preceding });
      }
    }

    if (!selectedMarker) continue;
    const openMarkerLength = selectedMarker.open.length;
    const contentStartIdx = earliestOpenIdx + openMarkerLength;
    const closeIdx = text.indexOf(selectedMarker.close, contentStartIdx);

    if (closeIdx !== -1) {
      const thinkingContent = text.slice(contentStartIdx, closeIdx);
      blocks.push({ type: 'thinking', content: thinkingContent });
      currentIndex = closeIdx + selectedMarker.close.length;
    } else {
      const thinkingContent = text.slice(contentStartIdx);
      blocks.push({ type: 'thinking', content: thinkingContent });
      currentIndex = text.length;
    }
  }

  return blocks;
}

export function getDisplayBlocks(
  blocks?: MessageBlock[],
  thinking?: string,
  tools?: ChatMessage['tools'],
  content?: string
): MessageBlock[] {
  try {
    const result: MessageBlock[] = [];
    let hasFinalContent = false;

    if (blocks && blocks.length > 0) {
      for (const block of blocks) {
        if (block.type === 'finalOutput' && block.content) {
          hasFinalContent = true;
          const parsed = parseSequentialText(block.content);
          for (const [subIndex, sub] of parsed.entries()) {
            result.push({
              id: `${block.id}_sub_${subIndex}_${sub.type}`,
              type: sub.type,
              content: sub.content
            });
          }
        } else {
          result.push(block);
        }
      }

      // Safety net: if blocks exist but none carried final text content,
      // inject the raw message content so it's never silently lost.
      if (!hasFinalContent && content && content.trim()) {
        const parsed = parseSequentialText(content);
        for (const [subIndex, sub] of parsed.entries()) {
          result.push({
            id: `safety_content_sub_${subIndex}_${sub.type}`,
            type: sub.type,
            content: sub.content
          });
        }
      }

      if (result.length > 0) return result;
    }

    // Fallback: build blocks from thinking, tools, and content
    const resultFallback: MessageBlock[] = [];
    if (thinking && thinking.trim()) {
      resultFallback.push({
        id: 'fallback_thinking',
        type: 'thinking',
        content: thinking.trim()
      });
    }

    if (tools && tools.length > 0) {
      for (const tool of tools) {
        const isCommand = tool.name.startsWith('@run_command') || tool.name.startsWith('run_command');
        resultFallback.push({
          id: `fallback_tool_${tool.id}`,
          type: isCommand ? 'command' : 'toolCall',
          tool: tool
        });
      }
    }

    if (content && content.trim()) {
      const parsed = parseSequentialText(content);
      for (const [subIndex, sub] of parsed.entries()) {
        resultFallback.push({
          id: `fallback_content_sub_${subIndex}_${sub.type}`,
          type: sub.type,
          content: sub.content
        });
      }
    }

    if (resultFallback.length > 0) return resultFallback;
  } catch (err) {
    console.error('Failed to parse blocks, falling back:', err);
  }

  return [{
    id: 'fallback_raw',
    type: 'finalOutput',
    content: content || ''
  }];
}

export function parseThinkingAndContent(rawContent: string, existingThinking?: string): { thinking: string; content: string } {
  const blocks = parseSequentialText(rawContent);
  let thinking = existingThinking || '';
  let content = '';

  for (const block of blocks) {
    if (block.type === 'thinking') {
      thinking += (thinking ? '\n' : '') + block.content;
    } else {
      content += block.content;
    }
  }

  return { thinking: thinking.trim(), content: content.trim() };
}

/* Long-message threshold used by the user bubble's collapse/expand toggle.
 * AI bubbles intentionally don't collapse — they always render in full. */
const LONG_MSG_THRESHOLD = 1000;

import { useState, useEffect, useMemo, useRef } from 'react';
import { useStore } from '@nanostores/react';
import { $sessions, updateSessionWorkspace } from '@/store/sessions';
import { FolderGit2, ChevronRight, ChevronDown, Folder, FolderOpen, FileText, AlertCircle, Trash2, FolderSearch, Link2 } from 'lucide-react';
import { isTauri } from '@/lib/tauri-detect';
import { toast } from 'sonner';

interface FlatFileNode {
  name: string;
  path: string;
  isDir: boolean;
  depth: number;
  isExpanded: boolean;
  sizeBytes?: number;
}

export function WorkspacePanel({ sessionId }: { sessionId: string | null }) {
  const sessions = useStore($sessions);
  const activeSession = useMemo(() => sessions.find(s => s.id === sessionId), [sessions, sessionId]);
  const workspacePath = activeSession?.workspacePath || null;

  const [flatTree, setFlatTree] = useState<FlatFileNode[]>([]);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);

  // Sync state with active session's workspace path
  useEffect(() => {
    if (workspacePath) {
      void loadRootFiles(workspacePath);
    } else {
      setFlatTree([]);
      setError(null);
    }
  }, [workspacePath, sessionId]);

  const loadRootFiles = async (dirPath: string) => {
    setLoading(true);
    setError(null);
    try {
      const res = await fetch(`/api/workspace/files?path=${encodeURIComponent(dirPath)}`);
      if (!res.ok) {
        const errData = await res.json().catch(() => ({}));
        throw new Error(errData.error || 'Failed to list directory contents');
      }
      const data = await res.json();
      setFlatTree(
        data.files.map((f: { name: string; path: string; isDir: boolean; sizeBytes?: number }) => ({
          name: f.name,
          path: f.path,
          isDir: f.isDir,
          depth: 0,
          isExpanded: false,
          sizeBytes: f.sizeBytes,
        }))
      );
    } catch (err) {
      const message = err instanceof Error ? err.message : String(err);
      setError(message);
      setFlatTree([]);
    } finally {
      setLoading(false);
    }
  };

  const handleClear = () => {
    if (!sessionId) return;
    updateSessionWorkspace(sessionId, null);
    setFlatTree([]);
    setError(null);
    toast.info('Workspace cleared for this session');
  };

  const toggleFolder = async (node: FlatFileNode, idx: number) => {
    if (node.isExpanded) {
      // Collapse
      const prefix = node.path + '/';
      setFlatTree(prev => {
        const next = prev.filter(n => !n.path.startsWith(prefix));
        next[idx] = { ...node, isExpanded: false };
        return next;
      });
    } else {
      // Expand
      try {
        const res = await fetch(`/api/workspace/files?path=${encodeURIComponent(node.path)}`);
        if (!res.ok) throw new Error('Failed to load subfolder');
        const data = await res.json();
        const subnodes = data.files.map((f: { name: string; path: string; isDir: boolean; sizeBytes?: number }) => ({
          name: f.name,
          path: f.path,
          isDir: f.isDir,
          depth: node.depth + 1,
          isExpanded: false,
          sizeBytes: f.sizeBytes,
        }));

        setFlatTree(prev => {
          const next = [...prev];
          next[idx] = { ...node, isExpanded: true };
          next.splice(idx + 1, 0, ...subnodes);
          return next;
        });
      } catch (err) {
        const message = err instanceof Error ? err.message : String(err);
        toast.error(`Could not read folder: ${node.name}: ${message}`);
      }
    }
  };

  const handleSetWorkspace = (folderPath: string) => {
    if (!sessionId) return;
    updateSessionWorkspace(sessionId, folderPath);
    toast.success('Workspace updated to subfolder');
  };

  const handleReferenceFile = (filePath: string) => {
    const event = new CustomEvent('august-insert-composer-text', {
      detail: ` @read_file ${filePath} `,
    });
    window.dispatchEvent(event);
    toast.info(`Referenced: ${filePath.split('/').pop()}`);
  };

  // Hidden file input for native folder picker (browser fallback)
  const dirInputRef = useRef<HTMLInputElement>(null);

  const handleSelectFolder = async () => {
    let selectedPath: string | null = null;

    if (isTauri) {
      try {
        const { invoke } = await import('@tauri-apps/api/core');
        selectedPath = await invoke<string | null>('select_directory');
      } catch (err) {
        console.error('Failed to open Tauri directory dialog:', err);
      }
    } else {
      dirInputRef.current?.click();
      return;
    }

    if (!selectedPath) return;
    selectedPath = selectedPath.trim();
    if (!selectedPath) return;

    const normalizedPath = selectedPath.replace(/\\/g, '/');
    const folderName = normalizedPath.split('/').pop() || 'workspace';

    const toastId = toast.loading(`Connecting to workspace: ${folderName}...`);

    try {
      const res = await fetch(`/api/workspace/files?path=${encodeURIComponent(normalizedPath)}`);
      if (!res.ok) {
        const errData = await res.json().catch(() => ({}));
        throw new Error(errData.error || 'Directory does not exist or is not readable');
      }

      toast.success(`Connected to workspace: ${folderName}`, { id: toastId });

      if (sessionId) {
        updateSessionWorkspace(sessionId, normalizedPath);
      }
    } catch (err) {
      const message = err instanceof Error ? err.message : String(err);
      toast.error(`Access failed: ${message}`, { id: toastId });
    }
  };

  const handleDirPicked = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;
    const fullPath = file.path
      || file.webkitRelativePath.slice(0, file.webkitRelativePath.indexOf('/'));
    if (!fullPath) return;
    const normalizedPath = fullPath.replace(/\\/g, '/');
    const folderName = normalizedPath.split('/').pop() || 'workspace';
    const toastId = toast.loading(`Connecting to workspace: ${folderName}...`);
    void (async () => {
      try {
        const res = await fetch(`/api/workspace/files?path=${encodeURIComponent(normalizedPath)}`);
        if (!res.ok) throw new Error((await res.json().catch(() => ({}))).error || 'Directory not accessible');
        toast.success(`Connected to workspace: ${folderName}`, { id: toastId });
        if (sessionId) updateSessionWorkspace(sessionId, normalizedPath);
      } catch (err) {
        const message = err instanceof Error ? err.message : String(err);
        toast.error(`Access failed: ${message}`, { id: toastId });
      }
    })();
    e.target.value = '';
  };

  const formatBytes = (bytes?: number) => {
    if (bytes === undefined || bytes === null) return '';
    if (bytes === 0) return '0 B';
    const k = 1024;
    const sizes = ['B', 'KB', 'MB'];
    const i = Math.floor(Math.log(bytes) / Math.log(k));
    return parseFloat((bytes / Math.pow(k, i)).toFixed(1)) + ' ' + sizes[i];
  };

  return (
    <div className="flex flex-col h-full bg-sidebar text-sm">
      <input
        ref={dirInputRef}
        type="file"
        webkitdirectory=""
        directory=""
        className="hidden"
        onChange={handleDirPicked}
      />
      {/* Header */}
      <div className="p-3 border-b border-border/40 flex items-center justify-between shrink-0 bg-background">
        <div className="flex items-center gap-2">
          <FolderGit2 className="size-4 text-warning/80" />
          <div className="flex flex-col">
            <span className="font-semibold text-foreground/80 text-[13px]">Workspace Explorer</span>
            {workspacePath && (
              <span className="text-[9px] text-muted-foreground/50 font-mono truncate max-w-[180px]" title={workspacePath}>
                {workspacePath.split(/[/\\]/).pop()}
              </span>
            )}
          </div>
        </div>
        {workspacePath && (
          <button
            onClick={handleClear}
            title="Disconnect Workspace"
            className="p-1 hover:bg-white/5 rounded text-muted-foreground hover:text-destructive transition"
          >
            <Trash2 className="size-3.5" />
          </button>
        )}
      </div>

      {/* Path Display / Connect Fallback */}
      <div className="p-3 border-b border-border/10 bg-sidebar shrink-0">
        {workspacePath ? (
          <div className="flex flex-col gap-0.5 min-w-0">
            <span className="text-[10px] text-muted-foreground/50 font-mono truncate" title={workspacePath}>
              {workspacePath}
            </span>
          </div>
        ) : (
          <div className="py-4 px-2 text-center text-muted-foreground/60 space-y-3">
            <p className="text-[12.5px]">No folder connected to this session.</p>
            <input
              type="text"
              placeholder="Paste path & press Enter (e.g. C:/my-project)..."
              className="w-full h-8 px-2.5 rounded border border-border/40 bg-muted/20 text-xs text-foreground placeholder:text-muted-foreground/45 outline-none focus:ring-1 focus:ring-primary/40 focus:border-primary transition"
              onKeyDown={(e) => {
                void (async () => {
                  if (e.key === 'Enter') {
                    const val = (e.target as HTMLInputElement).value.trim();
                    if (val) {
                      const normalized = val.replace(/\\/g, '/');
                      const folderName = normalized.split('/').pop() || 'workspace';
                      const toastId = toast.loading(`Connecting to workspace: ${folderName}...`);
                      try {
                        const res = await fetch(`/api/workspace/files?path=${encodeURIComponent(normalized)}`);
                        if (!res.ok) throw new Error('Directory does not exist or is not readable');
                        toast.success(`Connected to workspace: ${folderName}`, { id: toastId });
                        if (sessionId) {
                          updateSessionWorkspace(sessionId, normalized);
                          (e.target as HTMLInputElement).value = '';
                        }
                      } catch (err) {
                        const message = err instanceof Error ? err.message : String(err);
                        toast.error(`Access failed: ${message}`, { id: toastId });
                      }
                    }
                  }
                })();
              }}
            />
            <div className="relative flex items-center justify-center my-1">
              <span className="w-full h-[1px] bg-border/20 absolute" />
              <span className="text-[9px] uppercase px-2 bg-sidebar text-muted-foreground/60 relative font-bold">or</span>
            </div>
            <button
              onClick={() => { void handleSelectFolder(); }}
              className="w-full py-1.5 px-3 rounded-lg bg-primary text-primary-foreground font-semibold text-[10.5px] hover:opacity-95 active:scale-95 transition flex items-center justify-center gap-1.5 cursor-pointer"
            >
              <FolderGit2 className="size-3.5" />
              <span>Select Folder</span>
            </button>
          </div>
        )}
      </div>

      {/* Error Message */}
      {error && (
        <div className="flex items-start gap-2 text-destructive text-xs bg-destructive/10 border border-destructive/20 rounded-lg m-3 p-2.5">
          <AlertCircle className="size-4 shrink-0 mt-0.5" />
          <span>{error}</span>
        </div>
      )}

      {/* File Tree */}
      <div className="flex-1 overflow-y-auto p-1.5 scrollbar-thin">
        {workspacePath && !error && (
          <>
            {flatTree.length === 0 && !loading && (
              <div className="py-12 text-center text-muted-foreground/40 text-[11px] italic">
                No files found in this directory
              </div>
            )}
            {flatTree.map((node, i) => (
              <div
                key={node.path}
                className="group flex items-center justify-between rounded px-1.5 py-1 hover:bg-white/5 transition cursor-pointer text-foreground/80 hover:text-foreground"
                style={{ paddingLeft: `${node.depth * 10 + 6}px` }}
                onClick={() => { if (node.isDir) { void toggleFolder(node, i); } }}
              >
                <div className="flex items-center gap-2 min-w-0">
                  {node.isDir ? (
                    <>
                      {node.isExpanded ? (
                        <ChevronDown className="size-3 text-muted-foreground/60 shrink-0" />
                      ) : (
                        <ChevronRight className="size-3 text-muted-foreground/60 shrink-0" />
                      )}
                      {node.isExpanded ? (
                        <FolderOpen className="size-3.5 text-warning/80 shrink-0" />
                      ) : (
                        <Folder className="size-3.5 text-warning/80 shrink-0" />
                      )}
                    </>
                  ) : (
                    <>
                      <span className="w-3" />
                      <FileText className="size-3.5 text-muted-foreground/60 shrink-0" />
                    </>
                  )}
                  <span className="truncate text-[13px] font-mono">{node.name}</span>
                </div>

                <div className="flex items-center gap-2 shrink-0">
                  {!node.isDir && node.sizeBytes !== undefined && (
                    <span className="text-[9px] text-muted-foreground/45 font-mono">
                      {formatBytes(node.sizeBytes)}
                    </span>
                  )}

                  <div className="flex items-center gap-1 opacity-0 group-hover:opacity-100 transition-opacity">
                    {node.isDir ? (
                      <button
                        onClick={e => {
                          e.stopPropagation();
                          handleSetWorkspace(node.path);
                        }}
                        title="Set as active workspace path"
                        className="p-0.5 hover:bg-white/10 rounded text-primary hover:text-primary-foreground transition"
                      >
                        <FolderSearch className="size-3" />
                      </button>
                    ) : (
                      <button
                        onClick={e => {
                          e.stopPropagation();
                          handleReferenceFile(node.path);
                        }}
                        title="Reference in chat"
                        className="p-0.5 hover:bg-white/10 rounded text-muted-foreground hover:text-foreground transition"
                      >
                        <Link2 className="size-3" />
                      </button>
                    )}
                  </div>
                </div>
              </div>
            ))}
            {loading && (
              <div className="py-4 text-center text-muted-foreground/50 text-[12px] animate-pulse">
                Loading files...
              </div>
            )}
          </>
        )}
      </div>
    </div>
  );
}

import { atom } from 'nanostores';
import type { ChatMessage, MessageBlock } from '@/types/chat';
import type { WorkbenchMode, EffortLevel } from '@/types/chat';
import type { WorkbenchSession } from '@/types/workbench';
import { streamWorkbenchChat, streamWorkbenchReconnect, stopWorkbenchChat } from '@/api/workbench';
import { setSessionStatus, clearSessionStatus, $sessions } from '@/store/sessions';
import { makeStreamHandlers } from './makeStreamHandlers';
import { gitApi } from '@/api/git';
import { chatRuntime } from './chat-runtime';
import { pushBrowserAction } from '@/lib/browser-store';
import { upsertQueuedMessage, removeQueuedMessage } from './queue-store';

export interface SessionStreamState {
  messages: ChatMessage[];
  subagentPrompts: Map<string, {
    content: string;
    systemPrompt: string;
    userMessage: string;
    tokens: number;
    subagentId?: string;
    jobId?: string;
  }>;
  /** Live sub-agent containers keyed by the agent job id. Each container
   *  holds its own `blocks` array so thinking/text/toolCall/toolResult
   *  events for the sub-agent are rendered nested under the parent
   *  `august__spawn_subagent` / `august__run_team` tool call. */
  subagentBlocks: Map<string, SubagentBlockState>;
  toolProgress: Map<string, ReadonlyArray<ToolProgressEntry>>;
  workbenchBtw: WorkbenchBtwState | null;
  workbenchSession: WorkbenchSession | null;
}

export type {
  ChatMessage,
  MessageBlock,
  SubagentBlockState,
  ToolProgressEntry,
  WorkbenchBtwState,
} from '@/types/chat';
import type { SubagentBlockState, ToolProgressEntry, WorkbenchBtwState, AppendBlockEvent } from '@/types/chat';

/** Apply a React-style SetStateAction updater to a previous value. Mirrors
 *  the semantics of `React.Dispatch<React.SetStateAction<T>>` so the chat
 *  store layer can use the same calling convention. */
function applyUpdater<T>(updater: T | ((prev: T) => T), prev: T): T {
  return typeof updater === 'function' ? (updater as (prev: T) => T)(prev) : updater;
}

// Global store for the stream states of all sessions
export const $sessionStreamStates = atom<Record<string, SessionStreamState>>({});

// Keep track of active fetch AbortControllers on the client
export const activeStreamControllers = new Map<string, AbortController>();

/**
 * Per-session SSE subscriber that holds the live GET /api/workbench/chat/stream
 * connection. Independent of the per-turn AbortController above — detaching
 * this subscriber (e.g. when the user switches sessions) does NOT stop the
 * backend generation; the connection is just closed client-side. Other
 * subscribers (e.g. another tab) can re-attach via `sinceSeq` and replay
 * the missed events from the persistent chat-event-log.
 */
const sessionSubscribers = new Map<string, {
  controller: AbortController;
  lastSeq: number;
}>();

const LAST_SEQ_PREFIX = 'chat_last_seq_';
const SUB_LAST_SEQ = (sessionId: string) => `${LAST_SEQ_PREFIX}${sessionId}`;

function readLastSeq(sessionId: string): number {
  try {
    const raw = localStorage.getItem(SUB_LAST_SEQ(sessionId));
    const n = Number(raw);
    return Number.isFinite(n) && n > 0 ? n : 0;
  } catch (_) { return 0; }
}

function writeLastSeq(sessionId: string, seq: number) {
  if (!Number.isFinite(seq) || seq <= 0) return;
  try { localStorage.setItem(SUB_LAST_SEQ(sessionId), String(seq)); } catch { /* silent */ }
}

const MESSAGES_STORAGE_PREFIX = 'chat_messages_';

const messagesStorageKey = (sessionId: string | null) => sessionId ? `${MESSAGES_STORAGE_PREFIX}${sessionId}` : null;

export function loadMessagesForSession(sessionId: string | null): ChatMessage[] {
  const key = messagesStorageKey(sessionId);
  if (!key) return [];

  try {
    const saved = localStorage.getItem(key);
    if (saved) return JSON.parse(saved);
  } catch { /* silent */ }

  return [];
}

export function getOrInitSessionStreamState(sessionId: string | null): SessionStreamState {
  if (!sessionId) {
    return {
      messages: [],
      subagentPrompts: new Map(),
      subagentBlocks: new Map(),
      toolProgress: new Map(),
      workbenchBtw: null,
      workbenchSession: null,
    };
  }

  const current = $sessionStreamStates.get()[sessionId];
  if (current) return current;

  // Initialize from localStorage or defaults
  const initialMessages = loadMessagesForSession(sessionId);

  let workbenchSession: WorkbenchSession | null = null;
  const sessions = $sessions.get();
  const activeSession = sessions.find(s => s.id === sessionId);
  if (activeSession?.workbenchSessionId) {
    workbenchSession = {
      id: activeSession.workbenchSessionId,
      provider: (activeSession.workbenchProvider || 'claude'),
      agentId: activeSession.workbenchAgentId || 'build',
      agentRole: activeSession.workbenchAgentId || 'build',
      agentMode: 'assistant',
      approved: false,
      approvedAt: null,
      plan: null,
      goal: null,
      lastGoal: null,
      messageCount: 0,
      mutationCount: 0,
      lastMutationAt: null,
      updatedAt: new Date().toISOString(),
      todos: [],
      guardMode: 'full',
    };
  }

  const state: SessionStreamState = {
    messages: initialMessages,
    subagentPrompts: new Map(),
    subagentBlocks: new Map(),
    toolProgress: new Map(),
    workbenchBtw: null,
    workbenchSession,
  };

  $sessionStreamStates.set({
    ...$sessionStreamStates.get(),
    [sessionId]: state,
  });

  return state;
}

export function updateSessionStreamState(
  sessionId: string,
  updater: (prev: SessionStreamState) => Partial<SessionStreamState>
) {
  const current = getOrInitSessionStreamState(sessionId);
  const next = { ...current, ...updater(current) };
  $sessionStreamStates.set({
    ...$sessionStreamStates.get(),
    [sessionId]: next,
  });
}

function persistMessages(sessionId: string, messages: ChatMessage[]) {
  try {
    localStorage.setItem(`chat_messages_${sessionId}`, JSON.stringify(messages));
  } catch { /* silent */ }
}

// Check if we are currently streaming a session
export function isSessionStreaming(sessionId: string | null): boolean {
  if (!sessionId) return false;
  return activeStreamControllers.has(sessionId);
}

// Start a new chat generation
export async function startChatStream(
  sessionId: string,
  params: {
    message: string;
    chatHistory: ChatMessage[];
    workbenchMode: WorkbenchMode;
    effort: EffortLevel;
    model: string | undefined;
    modelProvider: string | undefined;
    getWorkbenchProvider: () => 'claude' | 'codex';
    ensureWorkbenchSession: () => Promise<WorkbenchSession | null>;
  }
) {
  if (activeStreamControllers.has(sessionId)) {
    if (chatRuntime.isSessionStreaming(sessionId)) {
      return;
    }
    activeStreamControllers.delete(sessionId);
  }

  setSessionStatus(sessionId, 'working');

  const assistantMsgId = `a${Date.now()}`;
  const abortController = new AbortController();
  activeStreamControllers.set(sessionId, abortController);

  const turn = chatRuntime.startTurn({
    sessionId,
    assistantMsgId,
    transport: 'none',
  });

  const { handlers, finalize } = makeStreamHandlers({
    sessionId,
    assistantMsgId,
    initialMessages: params.chatHistory,
    setMessages: (updater) => {
      updateSessionStreamState(sessionId, prev => {
        const nextMsgs = applyUpdater(updater, prev.messages);
        persistMessages(sessionId, nextMsgs);
        return { messages: nextMsgs };
      });
    },
    persistMessages,
    setSessionStatus,
    setWorkbenchSession: (session) => {
      updateSessionStreamState(sessionId, () => ({ workbenchSession: session }));
    },
    setSubagentPrompts: (updater) => {
      updateSessionStreamState(sessionId, prev => {
        const nextPrompts = applyUpdater(updater, prev.subagentPrompts);
        return { subagentPrompts: nextPrompts };
      });
    },
    setToolProgress: (updater) => {
      updateSessionStreamState(sessionId, prev => {
        const nextProgress = applyUpdater(updater, prev.toolProgress);
        return { toolProgress: nextProgress };
      });
    },
    setWorkbenchBtw: (btw) => {
      updateSessionStreamState(sessionId, () => ({ workbenchBtw: btw }));
    },
    isTurnVisible: () => true,
    finishTurn: (t, status) => {
      chatRuntime.finishTurn(t.turnId, status);
      activeStreamControllers.delete(sessionId);
    },
    turn,
    gitApi,
    streamUpdateIntervalMs: 24,
    appendBlockEvent,
  });

  try {
    const session = await params.ensureWorkbenchSession();
    if (!session) {
      updateSessionStreamState(sessionId, prev => ({
        messages: prev.messages.map(msg =>
          msg.id === assistantMsgId ? { ...msg, content: '⚠️ Could not initialize Workbench session.' } : msg
        )
      }));
      finalize('error');
      activeStreamControllers.delete(sessionId);
      return;
    }

    chatRuntime.setTransport(turn.turnId, 'http');

    const startResult = await streamWorkbenchChat({
      sessionId: session.id,
      message: params.message,
      provider: params.getWorkbenchProvider(),
      effort: params.effort,
      model: params.model,
      modelProvider: params.modelProvider,
    }, handlers, abortController.signal);

    // The POST handler returns { sinceSeq } JSON immediately and runs the
    // generation in the background. Live events are delivered via the
    // separate /api/workbench/chat/stream SSE channel — attach it now using
    // the same per-turn handlers so streamed text / thinking / toolUse /
    // toolResult events reach the chat UI. Without this, events accumulate
    // in the chat-event-log unread and the assistant bubble stays empty.
    //
    // Always attach the SSE subscriber when the POST didn't already consume
    // the event stream (legacy SSE POST body path sets consumedViaPost=true).
    // The backend handles missing/undefined sinceSeq by starting from the
    // current event log position.
    if (startResult?.consumedViaPost) {
      // Events were already delivered through the POST response body
      // (older backend / proxy without the JSON sinceSeq contract).
    } else {
      const reconnectSinceSeq = Number.isFinite(startResult?.sinceSeq)
        ? startResult.sinceSeq
        : undefined;
      if (reconnectSinceSeq === undefined) {
        console.warn('[startChatStream] POST succeeded without a valid sinceSeq — reconnecting from current position as fallback');
      }
      await streamWorkbenchReconnect(
        session.id,
        handlers,
        abortController.signal,
        reconnectSinceSeq
      );
    }

    finalize(abortController.signal.aborted ? 'aborted' : 'done');
  } catch (e) {
    if (e instanceof Error && e.name === 'AbortError') {
      clearSessionStatus(sessionId);
      finalize('aborted');
      return;
    }
    console.error('[startChatStream] error:', e);
    const errorMsg = e instanceof Error
      ? e.message
      : typeof e === 'string'
        ? e
        : 'Unknown error';
    updateSessionStreamState(sessionId, prev => ({
      messages: prev.messages.map(msg =>
        msg.id === assistantMsgId
          ? { ...msg, content: (msg.content || '') + `\n\n⚠️ Could not generate a response: ${errorMsg}` }
          : msg
      )
    }));
    // Also emit an error event through the handler so the onError path
    // in makeStreamHandlers can write the ⚠️ block into streamBlocks.
    try { handlers.onError?.({ message: errorMsg }); } catch { /* silent */ }
    finalize('error');
  } finally {
    activeStreamControllers.delete(sessionId);
  }
}

// Stop/abort generation for a session
export async function stopChatStream(sessionId: string) {
  const controller = activeStreamControllers.get(sessionId);
  if (controller) {
    controller.abort();
    activeStreamControllers.delete(sessionId);
  }

  const activeTurnId = chatRuntime.getLatestActiveTurnId(sessionId);
  const turn = activeTurnId ? chatRuntime.getTurn(activeTurnId) : null;
  if (turn) {
    chatRuntime.abortTurn(turn.turnId);
  }

  clearSessionStatus(sessionId);

  // Tell the backend to stop
  try {
    const state = getOrInitSessionStreamState(sessionId);
    const wbSessionId = state.workbenchSession?.id || sessionId;
    await stopWorkbenchChat(wbSessionId);
  } catch (err) {
    console.warn('Failed to notify backend of stop:', err);
  }
}

// Reconnect/sync stream with the backend
export async function reconnectChatStream(
  sessionId: string,
  _ensureWorkbenchSession: () => Promise<WorkbenchSession | null>
) {
  if (activeStreamControllers.has(sessionId)) {
    // Already active
    return;
  }

  const state = getOrInitSessionStreamState(sessionId);
  const messages = state.messages;
  const lastUserIdx = messages.map(m => m.role).lastIndexOf('user');
  const initialMessages = lastUserIdx !== -1 ? messages.slice(0, lastUserIdx + 1) : messages;

  let assistantMsgId = '';
  if (lastUserIdx !== -1 && lastUserIdx + 1 < messages.length) {
    assistantMsgId = messages[lastUserIdx + 1].id;
  } else {
    assistantMsgId = `a${Date.now()}`;
  }

  const turn = chatRuntime.startTurn({
    sessionId,
    assistantMsgId,
    transport: 'none',
  });

  // Use the turn's controller so aborting the turn also cancels fetches.
  const abortController = turn.controller;
  activeStreamControllers.set(sessionId, abortController);

  const { handlers, finalize } = makeStreamHandlers({
    sessionId,
    assistantMsgId,
    initialMessages,
    setMessages: (updater) => {
      updateSessionStreamState(sessionId, prev => {
        const nextMsgs = applyUpdater(updater, prev.messages);
        persistMessages(sessionId, nextMsgs);
        return { messages: nextMsgs };
      });
    },
    persistMessages,
    setSessionStatus,
    setWorkbenchSession: (session) => {
      updateSessionStreamState(sessionId, () => ({ workbenchSession: session }));
    },
    setSubagentPrompts: (updater) => {
      updateSessionStreamState(sessionId, prev => {
        const nextPrompts = applyUpdater(updater, prev.subagentPrompts);
        return { subagentPrompts: nextPrompts };
      });
    },
    setToolProgress: (updater) => {
      updateSessionStreamState(sessionId, prev => {
        const nextProgress = applyUpdater(updater, prev.toolProgress);
        return { toolProgress: nextProgress };
      });
    },
    setWorkbenchBtw: (btw) => {
      updateSessionStreamState(sessionId, () => ({ workbenchBtw: btw }));
    },
    isTurnVisible: () => true,
    finishTurn: (t, status) => {
      chatRuntime.finishTurn(t.turnId, status);
      activeStreamControllers.delete(sessionId);
    },
    turn,
    gitApi,
    streamUpdateIntervalMs: 24,
    appendBlockEvent,
  });

  try {
    chatRuntime.setTransport(turn.turnId, 'http');

    const lastSeq = getSessionSubscriberLastSeq(sessionId);
    await streamWorkbenchReconnect(sessionId, handlers, abortController.signal, lastSeq || undefined);
    finalize(abortController.signal.aborted ? 'aborted' : 'done');
  } catch (e) {
    if (e instanceof Error && e.name === 'AbortError') {
      clearSessionStatus(sessionId);
      finalize('aborted');
      return;
    }
    console.warn('Reconnect error:', e);
    finalize('done');
  } finally {
    activeStreamControllers.delete(sessionId);
  }
}

// Sync all active streams with the backend
export async function syncActiveStreams(_ensureWorkbenchSession: () => Promise<WorkbenchSession | null>) {
  try {
    const res = await fetch('/api/workbench/chat/active');
    if (!res.ok) return;
    const active: Record<string, string> = await res.json();
    for (const sessionId of Object.keys(active)) {
      if (active[sessionId] === 'streaming') {
        // Re-attach the per-session SSE subscriber if we don't have one.
        // The subscriber is independent of any per-turn AbortController —
        // it stays attached across tab/session switches and only detaches
        // when the backend reports the turn finished or the SSE closes.
        ensureSessionSubscriber(sessionId);
      }
    }
  } catch (err) {
    console.warn('Failed to sync active streams:', err);
  }
}

/**
 * Attach (or re-attach) the per-session SSE subscriber that pulls events
 * from GET /api/workbench/chat/stream. The subscriber is idempotent: if
 * one is already attached for `sessionId` it is left alone. The reducer
 * updates `subagentBlocks` (so background sub-agents appear in the chat
 * thread even when no per-turn handler is active) and bumps the stored
 * `lastSeq` so subsequent reconnects don't replay events.
 */
export function ensureSessionSubscriber(sessionId: string): void {
  if (!sessionId) return;
  if (sessionSubscribers.has(sessionId)) return;

  // Ensure there is an active turn in chatRuntime so the AUG streaming
  // indicator (WorkingIndicator) shows while the backend is generating.
  // Without this, a previous turn may have been finalized when the original
  // SSE connection dropped (tab switch, throttling), leaving isSessionStreaming
  // false even though the backend is still actively streaming and reconnecting
  // via this subscriber.
  let dummyTurnId: string | null = null;
  if (!chatRuntime.isSessionStreaming(sessionId)) {
    const assistantMsgId = `subscriber-${sessionId}-${Date.now()}`;
    const turn = chatRuntime.startTurn({
      sessionId,
      assistantMsgId,
      transport: 'none',
    });
    dummyTurnId = turn.turnId;
  }

  const controller = new AbortController();
  const sinceSeq = readLastSeq(sessionId);
  const entry = { controller, lastSeq: sinceSeq };
  sessionSubscribers.set(sessionId, entry);

  const handlers: import('@/types/workbench').WorkbenchEventHandlers = {
    onSeq: (seq) => {
      if (seq > entry.lastSeq) {
        entry.lastSeq = seq;
        writeLastSeq(sessionId, seq);
      }
    },
    onSubagentStart: (data) => {
      if (!data?.jobId) return;
      applySubagentEvent(sessionId, {
        type: 'subagentStart',
        jobId: data.jobId,
        agentId: data.agentId,
        parentToolUseId: data.parentToolUseId,
        scope: data.scope,
        task: data.task,
        depth: data.depth,
      });
    },
    onSubagentDone: (data) => {
      if (!data?.jobId) return;
      applySubagentEvent(sessionId, {
        type: 'subagentDone',
        jobId: data.jobId,
        status: data.status,
        message: data.message,
        result: data.result,
      });
    },
    onSubagentText: (data) => {
      if (!data?.jobId) return;
      applySubagentEvent(sessionId, {
        type: 'subagentText',
        jobId: data.jobId,
        content: data.content || '',
      });
    },
    onSubagentToolCall: (data) => {
      if (!data?.jobId) return;
      applySubagentEvent(sessionId, {
        type: 'subagentToolCall',
        jobId: data.jobId,
        id: data.id,
        name: data.name,
        input: data.input,
        status: data.status || 'running',
      });
    },
    onSubagentToolResult: (data) => {
      if (!data?.jobId) return;
      applySubagentEvent(sessionId, {
        type: 'subagentToolResult',
        jobId: data.jobId,
        id: data.id,
        content: data.content,
        isError: data.isError,
      status: data.status || (data.isError ? 'error' : 'done'),
        });
      },
      onCompaction: (_data) => {
        // Compaction events are handled by the per-turn handler
        // (makeStreamHandlers); the background subscriber acknowledges
        // them so the SSE stream stays healthy.
      },
      onWarning: (data) => {
        console.warn('[chat-stream-manager] warning:', data?.message || data);
      },
      onInfo: (data) => {
        console.info('[chat-stream-manager] info:', data?.message || data);
      },
      onBrowserAction: (data) => {
        pushBrowserAction({
          id: data.id,
          name: data.name,
          input: data.input,
          url: data.url,
          title: data.title,
          target: data.target ?? null,
          screenshot: data.screenshot ?? null,
          typed: data.typed,
          selected: data.selected,
          scrolled: data.scrolled,
          status: data.status,
          ts: Date.now(),
        });
      },
      onUserMessageQueued: (data) => {
        // A follow-up was queued (possibly from another tab or via the
        // optimistic local API call). Add it to the per-session queue
        // store so the UI pills update in real time.
        if (!data?.messageId || !data?.sessionId) return;
        upsertQueuedMessage(data.sessionId, {
          id: data.messageId,
          text: data.text ?? '',
          queuedAt: data.queuedAt ?? new Date().toISOString(),
        });
      },
      onUserMessageDequeued: (data) => {
        if (!data?.messageId || !data?.sessionId) return;
        removeQueuedMessage(data.sessionId, data.messageId);
      },
      onUserMessageInjected: (data) => {
        // The backend drained this message and appended it to the model's
        // in-flight conversation. Clear it from the local queue (it now
        // lives as an inline user bubble in the chat thread) and append
        // a synthetic user message to the session's message log so the
        // thread renders it in the right place.
        if (!data?.messageId || !data?.sessionId) return;
        removeQueuedMessage(data.sessionId, data.messageId);
        const entry = {
          id: `qm-${data.messageId}`,
          role: 'user' as const,
          content: data.text ?? '',
          timestamp: data.queuedAt ?? new Date().toISOString(),
          queued: true,
        };
        updateSessionStreamState(data.sessionId, (prev) => ({
          ...prev,
          messages: [...(prev.messages ?? []), entry],
        }));
      },
    };

  streamWorkbenchReconnect(sessionId, handlers, controller.signal, sinceSeq, {
    // Durable subscriber: effectively-unbounded retry with capped backoff.
    // The backend always emits a terminal event (done/error/aborted) when
    // the turn ends, so retries converge; a dead backend fails fast at the
    // POST /chat that started the turn. This keeps the stream bound to the
    // session across transient drops / tab switches (issue #2).
    maxRetries: Infinity,
  })
    .catch((err) => {
      if (err?.name !== 'AbortError') {
        console.warn('[chat-stream-manager] subscriber error:', err?.message || err);
      }
    })
    .finally(() => {
      // If the controller is still ours (not aborted), drop the entry so
      // a later sync can re-attach. Aborted means we intentionally stopped.
      if (!controller.signal.aborted) {
        sessionSubscribers.delete(sessionId);
      }
      // Finalize the turn we created above so isSessionStreaming reflects
      // the true state. The original stream's turn was already finalized
      // when it disconnected; this cleans up the subscriber-created turn.
      if (dummyTurnId) {
        chatRuntime.finishTurn(dummyTurnId, 'done');
      }
    });
}

export function detachSessionSubscriber(sessionId: string): void {
  const entry = sessionSubscribers.get(sessionId);
  if (!entry) return;
  entry.controller.abort();
  sessionSubscribers.delete(sessionId);
}

export function getSessionSubscriberLastSeq(sessionId: string): number {
  return sessionSubscribers.get(sessionId)?.lastSeq ?? readLastSeq(sessionId);
}

export function appendBlockEvent(
  prevBlocks: MessageBlock[],
  event: AppendBlockEvent
): MessageBlock[] {
  const blocks = [...prevBlocks];
  const lastBlock = blocks[blocks.length - 1];

  if (event.type === 'thinking') {
    const text = event.content || '';
    if (lastBlock && lastBlock.type === 'thinking') {
      lastBlock.content = (lastBlock.content || '') + text;
    } else {
      blocks.push({
        id: `b_think_${Date.now()}_${Math.random().toString(36).slice(2, 6)}`,
        type: 'thinking',
        content: text
      });
    }
    } else if (event.type === 'text' || event.type === 'content' || event.type === 'finalOutput') {
    const text = event.content || '';
    if (lastBlock && lastBlock.type === 'finalOutput') {
      lastBlock.content = (lastBlock.content || '') + text;
    } else {
      blocks.push({
        id: `b_out_${Date.now()}_${Math.random().toString(36).slice(2, 6)}`,
        type: 'finalOutput',
        content: text
      });
    }
  } else if (event.type === 'toolCall' || event.type === 'command') {
    const isCommand = event.type === 'command' || event.name?.startsWith('@run_command') || event.name?.startsWith('run_command');
    const existingIdx = blocks.findIndex(b => b.tool && b.tool.id === event.id);
    if (existingIdx !== -1) {
      const target = { ...blocks[existingIdx] };
      if (target.tool) {
        target.tool = {
          ...target.tool,
          context: event.context || target.tool.context || '',
          status: event.status || target.tool.status || 'running',
        };
      }
      blocks[existingIdx] = target;
    } else {
      blocks.push({
        id: `b_tool_${event.id || Date.now()}`,
        type: isCommand ? 'command' : 'toolCall',
        tool: {
          id: event.id || `tc_${Date.now()}`,
          name: event.name || 'tool',
          context: event.context || '',
          status: event.status || 'running',
          startedAt: Date.now()
        },
        ...(event.isRevisedPlan ? { isRevisedPlan: true } : {}),
      });
    }
  } else if (event.type === 'tool_progress') {
    const targetIdx = blocks.findIndex(b => b.tool && b.tool.id === event.id);
    if (targetIdx !== -1) {
      const target = { ...blocks[targetIdx] };
      if (target.tool) {
        target.tool = {
          ...target.tool,
          preview: (target.tool.preview || '') + (event.preview || '')
        };
      }
      blocks[targetIdx] = target;
    }
  } else if (event.type === 'toolResult') {
    const targetIdx = blocks.findIndex(b => b.tool && b.tool.id === event.id);
    if (targetIdx !== -1) {
      const target = { ...blocks[targetIdx] };
      if (target.tool) {
        target.tool = {
          ...target.tool,
          status: event.status || 'done',
          summary: event.summary || '',
          error: event.error || '',
          duration: event.duration,
          searchHits: event.searchHits ?? target.tool.searchHits,
        };
      }
      blocks[targetIdx] = target;
    }
  }

  return blocks;
}

/**
 * Apply a backend SSE event to the per-session `subagentBlocks` map. Used
 * by the per-session SSE subscriber (and by the per-turn reducer when it
 * wants to surface sub-agent events). Events that don't target a sub-agent
 * (no `jobId`) are no-ops.
 *
 * Returns `true` when the event mutated state, so callers can decide
 * whether to trigger a re-render.
 */
export function applySubagentEvent(
  sessionId: string,
  event:
    | { type: 'subagentStart'; jobId: string; agentId: string; parentToolUseId?: string; scope?: string; task?: string; depth?: number }
    | { type: 'subagent_thinking'; jobId: string; content?: string }
    | { type: 'subagentText'; jobId: string; content?: string }
    | { type: 'subagentToolCall'; jobId: string; id: string; name: string; input?: Record<string, unknown>; context?: string; status?: 'running' | 'done' | 'error' }
    | { type: 'subagentToolResult'; jobId: string; id: string; content?: unknown; isError?: boolean; status?: 'done' | 'error' | 'running'; summary?: string; error?: string; duration?: number }
    | { type: 'subagentDone'; jobId: string; status?: 'completed' | 'failed' | 'cancelled'; message?: string; result?: string }
): boolean {
  if (!sessionId || !event?.jobId) return false;
  const jobId = event.jobId;
  let mutated = false;

  if (event.type === 'subagentStart') {
    updateSessionStreamState(sessionId, (prev) => {
      const blocks = new Map(prev.subagentBlocks);
      if (blocks.has(jobId)) return {};
      blocks.set(jobId, {
        id: `sb_${jobId}`,
        jobId,
        parentToolId: event.parentToolUseId || `subagent-${jobId}`,
        agentId: event.agentId,
        scope: event.scope,
        task: event.task,
        depth: event.depth,
        status: 'running',
        startedAt: Date.now(),
        blocks: [],
      });
      mutated = true;
      return { subagentBlocks: blocks };
    });
    return mutated;
  }

  if (event.type === 'subagentDone') {
    updateSessionStreamState(sessionId, (prev) => {
      const blocks = new Map(prev.subagentBlocks);
      const current = blocks.get(jobId);
      if (!current) return {};
      const status = event.status === 'failed' ? 'failed'
        : event.status === 'cancelled' ? 'cancelled'
        : 'completed';
      blocks.set(jobId, {
        ...current,
        status,
        finishedAt: Date.now(),
        error: event.message,
      });
      mutated = true;
      return { subagentBlocks: blocks };
    });
    return mutated;
  }

  // For thinking/text/toolCall/toolResult events, mutate the inner
  // blocks array via appendBlockEvent (same reducer as the parent).
  updateSessionStreamState(sessionId, (prev) => {
    const blocks = new Map(prev.subagentBlocks);
    const current = blocks.get(jobId);
    if (!current) return {};
    if (event.type === 'subagent_thinking') {
      const inner = appendBlockEvent(current.blocks, { type: 'thinking', content: event.content || '' });
      blocks.set(jobId, { ...current, blocks: inner });
      mutated = true;
    } else if (event.type === 'subagentText') {
      const inner = appendBlockEvent(current.blocks, { type: 'text', content: event.content || '' });
      blocks.set(jobId, { ...current, blocks: inner });
      mutated = true;
    } else if (event.type === 'subagentToolCall') {
      const context = event.context
        || (event.input && Object.keys(event.input).length > 0
          ? JSON.stringify(event.input, null, 2)
          : '');
      const inner = appendBlockEvent(current.blocks, {
        type: 'toolCall',
        id: event.id,
        name: event.name,
        context,
        status: event.status || 'running',
      });
      blocks.set(jobId, { ...current, blocks: inner });
      mutated = true;
    } else if (event.type === 'subagentToolResult') {
      const resultStr = typeof event.content === 'string'
        ? event.content
        : event.content != null ? JSON.stringify(event.content) : '';
      const inner = appendBlockEvent(current.blocks, {
        type: 'toolResult',
        id: event.id,
        status: (event.status || (event.isError ? 'error' : 'done')),
        summary: event.summary || resultStr.slice(0, 240),
        error: event.error || (event.isError ? resultStr.slice(0, 240) : ''),
        duration: event.duration,
      });
      blocks.set(jobId, { ...current, blocks: inner });
      mutated = true;
    }
    return { subagentBlocks: blocks };
  });
  return mutated;
}

// ── Resilience: re-attach SSE subscribers on tab refocus / network recovery ──
//
// A dropped per-turn stream (tab switch, throttling, brief network blip) used
// to finalize the turn as errored even though the backend kept generating.
// The durable per-session subscriber (ensureSessionSubscriber, unbounded
// retries) keeps the stream bound to the session, but it only gets re-attached
// if something calls syncActiveStreams. We trigger that here on:
//   * visibilitychange (document refocus / tab switch back)
//   * online (network recovered after going offline)
// in addition to the existing poller. This is the frontend half of issue #2:
// long tool→think cycles stay live across interruptions.

let _registeredEnsureSession: ((sessionId: string) => Promise<WorkbenchSession | null>) | null = null;
let _resyncListenersAttached = false;

/** Register the ensureWorkbenchSession callback used by the auto-resync
 *  listeners, and attach the window listeners (idempotently). Called once
 *  at app init with the real session-ensure function. */
export function registerStreamResync(
  ensureWorkbenchSession: (sessionId: string) => Promise<WorkbenchSession | null>,
): void {
  _registeredEnsureSession = ensureWorkbenchSession;
  if (_resyncListenersAttached || typeof window === 'undefined') return;
  _resyncListenersAttached = true;

  const resync = () => {
    if (typeof document !== 'undefined' && document.visibilityState === 'hidden') return;
    // syncActiveStreams accepts a no-arg ensureWorkbenchSession; wrap ours.
    void syncActiveStreams(() => _registeredEnsureSession
      ? _registeredEnsureSession('')
      : Promise.resolve(null));
  };

  window.addEventListener('visibilitychange', resync);
  window.addEventListener('online', resync);
}

/**
 * makeStreamHandlers — factory for the per-turn Workbench SSE handler
 * bundle used by both the composer (`ChatThread.handleSend` →
 * `generateAIResponse`) and the plan banner click handlers
 * (`onAccept` / `onAcceptAndImplement` / `onReject` / `onRevise`).
 *
 * Why a factory (not a hook): each turn is a self-contained stream
 * whose closure state (streamBlocks, toolResults, thinkingContent, …)
 * is created fresh per call and discarded when `finalize()` resolves.
 * A React hook would force this state into refs + useState, adding
 * ceremony and rules-of-hooks pitfalls. A plain factory keeps the
 * closure in scope exactly as the composer originally had it.
 *
 * The factory returns:
 *   - `handlers`: the full `WorkbenchEventHandlers` bundle the SSE
 *     reader passes events to. Every event is rendered into the
 *     chat thread via the same reducer (`appendBlockEvent`) the
 *     composer uses.
 *   - `finalize(status)`: called once when the stream ends (or
 *     errors). Writes the final accumulated state into the
 *     assistant message and updates the session status.
 *   - `getState()`: exposes the live per-turn state for callers
 *     that need it.
 *
 * The factory does NOT start the stream itself. The caller drives
 * the stream and then calls `finalize` exactly once.
 */

import type { ChatMessage, MessageBlock, WorkbenchBtwState, AppendBlockEvent } from '@/types/chat';
import type { ChatTurnRecord } from './chat-runtime';
import type { WorkbenchEventHandlers, WorkbenchSession } from '@/types/workbench';
import type { GitDiffResult } from '@/api/git';
import type { ToolProgressEvent, ToolProgressMap } from '@/lib/tool-progress';
import { applyToolProgress } from '@/lib/tool-progress';
import { pushBrowserAction } from '@/lib/browser-store';
import { applySubagentEvent } from './chat-stream-manager';

export interface MakeStreamHandlersOptions {
  sessionId: string;
  assistantMsgId: string;
  /** Current messages at turn start. The factory pushes a placeholder
   *  assistant message and returns the new array via `getNextMessages()`. */
  initialMessages: ChatMessage[];
  setMessages: React.Dispatch<React.SetStateAction<ChatMessage[]>>;
  /** Persist a messages array to durable storage. The factory calls
   *  this on placeholder push and on queue-drain so refresh restores
   *  the right state. */
  persistMessages: (sessionId: string, messages: ChatMessage[]) => void;

  setSessionStatus: (sessionId: string, status: 'idle' | 'working' | 'awaiting' | 'error' | 'done') => void;

  setWorkbenchSession: (session: WorkbenchSession | null) => void;
  setSubagentPrompts: React.Dispatch<React.SetStateAction<Map<string, {
    content: string;
    systemPrompt: string;
    userMessage: string;
    tokens: number;
    subagentId?: string;
    jobId?: string;
  }>>>;
  setToolProgress: React.Dispatch<React.SetStateAction<ToolProgressMap>>;
  setWorkbenchBtw: (result: WorkbenchBtwState | null) => void;

  isTurnVisible: (sessionId: string) => boolean;
  finishTurn: (turn: ChatTurnRecord, status: 'done' | 'error' | 'aborted') => void;
  turn: ChatTurnRecord;



  gitApi: { diff: (sessionId: string) => Promise<GitDiffResult> };
  streamUpdateIntervalMs: number;
  initialMutationCount?: number;

  /** Pure reducer that merges a new SSE event into the streamBlocks
   *  array. Lives in ChatThread.tsx so the composer and the factory
   *  share the exact same merging behavior. */
  appendBlockEvent: (prev: MessageBlock[], event: AppendBlockEvent) => MessageBlock[];
}

export interface StreamHandlers {
  handlers: WorkbenchEventHandlers;
  finalize: (status: 'done' | 'error' | 'aborted') => void;
  getState: () => {
    streamBlocks: MessageBlock[];
    assistantContent: string;
    thinkingContent: string;
    toolResults: NonNullable<ChatMessage['tools']>;
    changedFiles: GitDiffResult | null;
  };
}

export function makeStreamHandlers(opts: MakeStreamHandlersOptions): StreamHandlers {
  const {
    sessionId,
    assistantMsgId,
    initialMessages,
    setMessages,
    persistMessages,
    setSessionStatus,
    setWorkbenchSession,
    setSubagentPrompts,
    setToolProgress,
    setWorkbenchBtw,
    isTurnVisible,
    finishTurn,
    turn,

    gitApi,
    streamUpdateIntervalMs,
    initialMutationCount,
    appendBlockEvent,
  } = opts;

  // Per-turn closure state.
  let assistantContent = '';
  let thinkingContent = '';
  let toolResults: NonNullable<ChatMessage['tools']> = [];
  const pendingConfirmations = new Map<string, { message?: string; detail?: string; confirmationToken?: string }>();
  let streamBlocks: MessageBlock[] = [];
  let changedFiles: GitDiffResult | null = null;
  const beforeMutationCount = initialMutationCount ?? 0;
  let latestMutationCount = 0;
  let latestWorkbenchTodos: NonNullable<ChatMessage['todos']> = [];
  const thinkingStart = Date.now();
  let thinkingEnd: number | null = null;
  let finished = false;

  // Push the assistant placeholder into message state so the bubble
  // exists from frame 0. Persist to storage so refresh restores it.
  const placeholder: ChatMessage = {
    id: assistantMsgId,
    role: 'assistant',
    content: '',
    timestamp: new Date().toISOString(),
  };
  const nextMessages = [...initialMessages, placeholder];
  setMessages(nextMessages);
  persistMessages(sessionId, nextMessages);
  setSubagentPrompts(new Map());

  // ---- update / scheduleUpdate (throttled flush to React state) ----
  let updateTimeout: number | null = null;
  let lastFlushAt = 0;
  const update = () => {
    setMessages(prev => prev.map(msg =>
      msg.id === assistantMsgId ? {
        ...msg,
        content: assistantContent,
        thinking: thinkingContent || undefined,
        tools: toolResults && toolResults.length > 0 ? toolResults : undefined,
        blocks: streamBlocks,
        todos: latestWorkbenchTodos.length > 0 ? latestWorkbenchTodos : undefined,
        changedFiles: changedFiles || undefined,
      } : msg
    ));
  };
  const flushUpdate = () => {
    updateTimeout = null;
    lastFlushAt = (typeof performance !== 'undefined' ? performance.now() : Date.now());
    update();
  };
  const scheduleUpdate = () => {
    if (updateTimeout !== null) return;
    const now = (typeof performance !== 'undefined' ? performance.now() : Date.now());
    const delay = Math.max(0, streamUpdateIntervalMs - (now - lastFlushAt));
    updateTimeout = window.setTimeout(flushUpdate, delay);
  };
  const cancelPendingUpdate = () => {
    if (updateTimeout !== null) {
      window.clearTimeout(updateTimeout);
      updateTimeout = null;
    }
  };

  const finalize = (status: 'done' | 'error' | 'aborted') => {
    if (finished) return;
    finished = true;
    cancelPendingUpdate();
    setMessages(prev => prev.map(msg =>
      msg.id === assistantMsgId ? {
        ...msg,
        content: assistantContent || msg.content,
        thinking: thinkingContent || undefined,
        thinkingDuration: thinkingEnd
          ? Math.round((thinkingEnd - thinkingStart) / 100) / 10
          : thinkingContent.trim()
            ? Math.round((Date.now() - thinkingStart) / 100) / 10
            : undefined,
        tools: toolResults && toolResults.length > 0 ? toolResults : undefined,
        blocks: streamBlocks,
        todos: latestWorkbenchTodos.length > 0 ? latestWorkbenchTodos : undefined,
        changedFiles: changedFiles || undefined,
      } : msg
    ));
    if (status === 'done' || status === 'error') {
      if (isTurnVisible(sessionId)) setSessionStatus(sessionId, status === 'done' ? 'done' : 'error');
    }
    finishTurn(turn, status);

  };

  const handlers: WorkbenchEventHandlers = {
    onPrompt: ({ content, systemPrompt, userMessage, tokens, toolUseId, subagentId, jobId }) => {
      const key = toolUseId || (jobId ? `subagent-${jobId}` : `prompt-${Date.now()}-${Math.random().toString(36).slice(2, 8)}`);
      setSubagentPrompts(prev => {
        const next = new Map(prev);
        next.set(key, {
          content,
          systemPrompt: systemPrompt ?? '',
          userMessage: userMessage ?? '',
          tokens: tokens ?? 0,
          subagentId: subagentId || undefined,
          jobId: jobId || undefined,
        });
        return next;
      });
      // Also seed the live sub-agent container so the parent tool call
      // can render the nested block immediately, even if a separate
      // `subagentStart` event arrives later (or was missed during a
      // reconnect).
      if (jobId) {
        applySubagentEvent(sessionId, {
          type: 'subagentStart',
          jobId,
          agentId: subagentId || 'subagent',
          parentToolUseId: toolUseId,
        });
      }
    },
    onSubagentStart: (data) => {
      if (!data?.jobId) return;
      applySubagentEvent(sessionId, {
        type: 'subagentStart',
        jobId: data.jobId,
        agentId: data.agentId,
        parentToolUseId: data.parentToolUseId,
        scope: data.scope,
        task: data.task,
        depth: data.depth,
      });
    },
    onSubagentDone: (data) => {
      if (!data?.jobId) return;
      applySubagentEvent(sessionId, {
        type: 'subagentDone',
        jobId: data.jobId,
        status: data.status,
        message: data.message,
        result: data.result,
      });
    },
    onSubagentText: (data) => {
      if (!data?.jobId) return;
      applySubagentEvent(sessionId, {
        type: 'subagentText',
        jobId: data.jobId,
        content: data.content || '',
      });
    },
    onSubagentToolCall: (data) => {
      if (!data?.jobId) return;
      applySubagentEvent(sessionId, {
        type: 'subagentToolCall',
        jobId: data.jobId,
        id: data.id,
        name: data.name,
        input: data.input,
        status: data.status || 'running',
      });
    },
    onSubagentToolResult: (data) => {
      if (!data?.jobId) return;
      applySubagentEvent(sessionId, {
        type: 'subagentToolResult',
        jobId: data.jobId,
        id: data.id,
        content: data.content,
        isError: data.isError,
        status: data.status || (data.isError ? 'error' : 'done'),
      });
    },
    onStarted: ({ sinceSeq }) => {
      // The backend reports the seq of the 'started' event so callers
      // can attach an SSE subscriber that doesn't replay already-seen
      // events. We don't need to act on it here (the subscriber is
      // independent), but we expose it for debugging via a console hint.
      if (Number.isFinite(sinceSeq)) {
         
        console.debug('[makeStreamHandlers] chat turn started at seq', sinceSeq);
      }
    },
    onThinking: ({ content }) => {
      // Skip empty thinking deltas — they create a visible thinking block
      // with no text content and no way to dismiss it.
      if (!content) return;
      if (!thinkingEnd && content.trim()) {
        thinkingEnd = Date.now();
      }
      thinkingContent += content;
      streamBlocks = appendBlockEvent(streamBlocks, { type: 'thinking', content });
      scheduleUpdate();
    },
    onText: ({ content }) => {
      if (!thinkingEnd && thinkingContent.trim()) {
        thinkingEnd = Date.now();
      }
      assistantContent += content;
      streamBlocks = appendBlockEvent(streamBlocks, { type: 'finalOutput', content });
      scheduleUpdate();
    },
    onToolUse: ({ id, name, input }) => {
      const existingIdx = toolResults.findIndex(t => t.id === id);
      const toolEntry = {
        name,
        context: JSON.stringify(input || {}, null, 2),
        id,
        status: 'running' as const,
        summary: Object.keys(input || {}).join(', '),
        error: '',
        startedAt: existingIdx !== -1 ? toolResults[existingIdx].startedAt : Date.now(),
      };
      if (existingIdx !== -1) {
        toolResults = toolResults.map((t, idx) => idx === existingIdx ? toolEntry : t);
      } else {
        toolResults = [...toolResults, toolEntry];
      }

      streamBlocks = appendBlockEvent(streamBlocks, {
        type: name.startsWith('@run_command') || name.startsWith('run_command') ? 'command' : 'toolCall',
        name,
        id,
        context: JSON.stringify(input || {}, null, 2),
        status: 'running',
      });
      scheduleUpdate();
    },
    onToolResult: ({ id, content, isError }) => {
      let parsedResult: any;
      try {
        parsedResult = typeof content === 'string' ? JSON.parse(content) : content;
      } catch {
        parsedResult = null;
      }

      if (parsedResult?.type === 'mutation_pending_confirmation') {
        pendingConfirmations.set(id, {
          message: parsedResult.message,
          detail: parsedResult.detail,
          confirmationToken: parsedResult.confirmationToken,
        });
      } else {
        pendingConfirmations.delete(id);
      }

      const resultText = typeof content === 'string' ? content : content != null ? JSON.stringify(content) : '';

      // Extract search hits from structured web_search JSON result
      let searchHits: Array<{ title: string; url: string; snippet?: string }> | undefined;
      const toolEntry = toolResults.find(t => t.id === id);
      if (toolEntry && (toolEntry.name === 'web_search' || toolEntry.name === 'WebSearch')) {
        if (parsedResult && Array.isArray(parsedResult.results)) {
          searchHits = parsedResult.results.map((r: { title?: string; url?: string; snippet?: string }) => ({
            title: r.title || r.snippet || '',
            url: r.url || '',
            snippet: r.snippet || '',
          }));
        }
      }

      toolResults = toolResults.map(t => t.id === id ? {
        ...t,
        pendingApproval: parsedResult?.type === 'mutation_pending_confirmation' ? {
          message: parsedResult.message,
          detail: parsedResult.detail,
          confirmationToken: parsedResult.confirmationToken,
        } : undefined,
        status: isError && !parsedResult?.type ? 'error' : 'done',
        result: resultText,
        error: isError && !parsedResult?.type ? resultText : '',
        duration: t.startedAt ? Date.now() - t.startedAt : undefined,
        searchHits: searchHits ?? t.searchHits,
      } : t);
      streamBlocks = appendBlockEvent(streamBlocks, {
        type: 'toolResult',
        id,
        status: isError && !parsedResult?.type ? 'error' : 'done',
        summary: resultText.slice(0, 240),
        error: isError && !parsedResult?.type ? resultText.slice(0, 240) : '',
        duration: toolResults.find(t => t.id === id)?.duration,
        searchHits,
      });
      scheduleUpdate();
    },
    onSession: (sessionState) => {
      latestWorkbenchTodos = sessionState.todos ?? [];
      latestMutationCount = sessionState.mutationCount;
      setWorkbenchSession(sessionState);
      scheduleUpdate();
    },
    onBrowserAction: (data) => {
      pushBrowserAction({
        id: data.id,
        name: data.name,
        input: data.input,
        url: data.url,
        title: data.title,
        target: data.target ?? null,
        screenshot: data.screenshot ?? null,
        typed: data.typed,
        selected: data.selected,
        scrolled: data.scrolled,
        status: data.status,
        ts: Date.now(),
      });
    },
    onToolProgress: (event) => {
      const e: ToolProgressEvent = {
        id: event.id,
        phase: event.phase,
        paths: event.paths,
        path: event.path,
      };
      setToolProgress(prev => applyToolProgress(prev, e));
    },
    onBtw: (result) => {
      setWorkbenchBtw(result);
    },
    onCompaction: (info) => {
      // When the summarizing compressor collapses the middle of the
      // conversation, surface a small inline notice so the user can see
      // it happened. The notice is part of the assistant turn so it
      // disappears if the turn is rolled back.
      const notice = `\n\n📦 Context compacted — kept the first ${info.headCount} and last ${info.tailCount} messages; summarized ${info.compressedCount} middle messages (~${info.originalTokens} → ~${info.compressedTokens} tokens).`;
      assistantContent += notice;
      streamBlocks = appendBlockEvent(streamBlocks, { type: 'finalOutput', content: notice });
      scheduleUpdate();
    },
    onWarning: ({ message }) => {
      const warning = `\n\n⚠️ ${message || 'Warning'}`;
      assistantContent += warning;
      streamBlocks = appendBlockEvent(streamBlocks, { type: 'finalOutput', content: warning });
      scheduleUpdate();
    },
    onInfo: ({ message }) => {
      const info = `\n\nℹ️ ${message || ''}`;
      assistantContent += info;
      streamBlocks = appendBlockEvent(streamBlocks, { type: 'finalOutput', content: info });
      scheduleUpdate();
    },
    onDone: () => {
      void (async () => {
        if (latestMutationCount > beforeMutationCount && sessionId) {
          try {
            const diff = await gitApi.diff(sessionId);
            if (diff.files.length > 0) changedFiles = diff;
          } catch (e) {
            console.warn('[makeStreamHandlers] Failed to load changed files:', e);
          }
        }
        finalize('done');
      })();
    },
    onError: ({ message }) => {
      assistantContent += `\n\n⚠️ Workbench error: ${message}`;
      streamBlocks = appendBlockEvent(streamBlocks, { type: 'finalOutput', content: `\n\n⚠️ Workbench error: ${message}` });
      scheduleUpdate();
      finalize('error');
    },
  };

  return {
    handlers,
    finalize,
    getState: () => ({ streamBlocks, assistantContent, thinkingContent, toolResults, changedFiles }),
  };
}

import { useState, useCallback } from 'react';
import { X, HelpCircle, CheckCircle2, XCircle, ChevronRight, Lightbulb, Plus } from 'lucide-react';

interface Question {
  id: number;
  stem: string;
  options: string[];
}

interface AnswerResult {
  correct?: boolean;
  isCorrect?: boolean;
  correctIndex: number;
  rationale: string;
}

interface ExamBannerProps {
  examId: number;
  question: Question;
  onAnswer: (questionId: number, selectedIndex: number) => Promise<AnswerResult>;
  onNext: () => void;
  onAddQuestion: (request: string) => Promise<void>;
  onDismiss: () => void;
}

export function ExamBanner({ examId, question, onAnswer, onNext, onAddQuestion, onDismiss }: ExamBannerProps) {
  const [selected, setSelected] = useState<number | null>(null);
  const [answerResult, setAnswerResult] = useState<AnswerResult | null>(null);
  const [helpText, setHelpText] = useState('');
  const [showExplanation, setShowExplanation] = useState(false);
  const [explanation, setExplanation] = useState('');
  const [addRequest, setAddRequest] = useState('');
  const [isSubmitting, setIsSubmitting] = useState(false);

  const isCorrect = answerResult
    ? (answerResult.isCorrect ?? answerResult.correct ?? false)
    : false;

  const handleSelect = useCallback(async (index: number) => {
    if (answerResult) return; // already answered
    setSelected(index);
    setIsSubmitting(true);
    try {
      const result = await onAnswer(question.id, index);
      setAnswerResult(result);
    } catch {
      setAnswerResult({ isCorrect: false, correctIndex: 0, rationale: 'Error checking answer.' });
    }
    setIsSubmitting(false);
  }, [question.id, answerResult, onAnswer]);

  const handleHelp = useCallback(async () => {
    if (!helpText.trim()) return;
    setIsSubmitting(true);
    try {
      const res = await fetch(`/api/exam/${examId}/help`, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ questionId: question.id, ask: helpText }),
      });
      if (res.ok) {
        const data = await res.json();
        setExplanation(data.explanation || 'No explanation available.');
      } else {
        setExplanation('Unable to get help right now.');
      }
      setShowExplanation(true);
    } catch {
      setExplanation('Unable to get help right now.');
      setShowExplanation(true);
    }
    setIsSubmitting(false);
  }, [examId, question.id, helpText]);

  const handleAddQuestion = useCallback(async () => {
    if (!addRequest.trim()) return;
    setIsSubmitting(true);
    try {
      await onAddQuestion(addRequest);
      setAddRequest('');
    } catch { /* silent */ }
    setIsSubmitting(false);
  }, [addRequest, onAddQuestion]);

  return (
    <>
      {/* Banner */}
      <div className="fixed bottom-0 left-0 right-0 z-50 border-t border-border bg-card shadow-2xl animate-slide-up">
        <div className="mx-auto max-w-3xl p-4 space-y-4">
          {/* Header */}
          <div className="flex items-center justify-between">
            <div className="flex items-center gap-2">
              <Lightbulb className="size-4 text-warning" />
              <span className="text-sm font-medium">Exam Mode</span>
            </div>
            <button onClick={onDismiss} className="text-muted-foreground hover:text-foreground transition">
              <X className="size-4" />
            </button>
          </div>

          {/* Question stem */}
          <p className="text-sm leading-relaxed">{question.stem}</p>

          {/* Options */}
          <div className="space-y-2">
            {question.options.map((opt, i) => {
              let className = 'w-full text-left px-3 py-2 rounded-lg border text-sm transition-colors ';
              if (answerResult === null) {
                className += 'border-border hover:border-primary hover:bg-accent/30 cursor-pointer';
              } else if (i === answerResult.correctIndex) {
                className += 'border-success bg-success/10 text-success';
              } else if (i === selected && !isCorrect) {
                className += 'border-danger bg-danger/10 text-danger';
              } else {
                className += 'border-border opacity-50';
              }
              return (
                <button key={i} onClick={() => { void handleSelect(i); }} className={className} disabled={answerResult !== null || isSubmitting}>
                  <span className="flex items-center gap-2">
                    {answerResult !== null && i === answerResult.correctIndex && <CheckCircle2 className="size-3.5 shrink-0" />}
                    {answerResult !== null && i === selected && !isCorrect && <XCircle className="size-3.5 shrink-0" />}
                    <span className="text-xs font-medium text-muted-foreground w-5">{String.fromCharCode(65 + i)}.</span>
                    {opt}
                  </span>
                </button>
              );
            })}
          </div>

          {/* Result + Next */}
          {answerResult && (
            <div className="flex items-center justify-between">
              <p className={`text-xs ${isCorrect ? 'text-success' : 'text-danger'}`}>
                {isCorrect ? 'Correct!' : 'Incorrect'}
              </p>
              <button onClick={onNext} className="flex items-center gap-1 text-xs font-medium text-primary hover:underline">
                <span>Next</span>
                <ChevronRight className="size-3" />
              </button>
            </div>
          )}

          {/* Help input */}
          <div className="flex items-center gap-2">
            <input
              type="text"
              value={helpText}
              onChange={(e) => setHelpText(e.target.value)}
              placeholder="Ask the model for help…"
              className="flex-1 bg-muted border border-border rounded-lg px-3 py-1.5 text-xs outline-none focus:border-ring transition"
              onKeyDown={(e) => { if (e.key === 'Enter') { void handleHelp(); } }}
            />
            <button onClick={() => { void handleHelp(); }} disabled={isSubmitting || !helpText.trim()} className="text-primary hover:underline text-xs font-medium shrink-0">
              <HelpCircle className="size-4" />
            </button>
          </div>

          {/* Add question input */}
          <div className="flex items-center gap-2 border-t border-border pt-2">
            <input
              type="text"
              value={addRequest}
              onChange={(e) => setAddRequest(e.target.value)}
              placeholder="Add a question about…"
              className="flex-1 bg-transparent text-xs text-muted-foreground outline-none placeholder:text-muted-foreground/50"
              onKeyDown={(e) => { if (e.key === 'Enter') { void handleAddQuestion(); } }}
            />
            <button onClick={() => { void handleAddQuestion(); }} disabled={isSubmitting || !addRequest.trim()} className="text-primary hover:underline text-xs font-medium shrink-0">
              <Plus className="size-3.5" />
            </button>
          </div>
        </div>
      </div>

      {/* Explanation modal (overlay, non-blocking) */}
      {showExplanation && (
        <div className="fixed inset-0 z-[60] flex items-center justify-center bg-black/30" onClick={() => setShowExplanation(false)}>
          <div className="bg-card border border-border rounded-xl shadow-2xl max-w-lg w-full mx-4 p-5 space-y-3 animate-in fade-in zoom-in-95" onClick={(e) => e.stopPropagation()}>
            <div className="flex items-center justify-between">
              <h3 className="text-sm font-medium">Explanation</h3>
              <button onClick={() => setShowExplanation(false)} className="text-muted-foreground hover:text-foreground">
                <X className="size-4" />
              </button>
            </div>
            <div className="text-xs text-muted-foreground leading-relaxed whitespace-pre-wrap">{explanation}</div>
            {answerResult && (
              <p className={`text-xs font-medium ${isCorrect ? 'text-success' : 'text-danger'}`}>
                {isCorrect ? '✓ You got it right' : '✗ Keep studying'}
              </p>
            )}
            <button onClick={() => setShowExplanation(false)} className="w-full mt-2 py-2 text-xs font-medium bg-primary text-primary-foreground rounded-lg hover:opacity-90 transition">
              Got it
            </button>
          </div>
        </div>
      )}
    </>
  );
}

/* v3 — ExamHost: manages exam lifecycle (generate → fetch → answer → next).
   Wraps the controlled ExamBanner with state for examId, current question,
   total questions, and progression. Used by ChatThread when the user types
   `/Exam` (with optional topic or file paths). */
import { useEffect, useState, useCallback } from 'react';
import { ExamBanner } from './ExamBanner';

interface Question {
  id: number;
  examId?: number;
  position?: number;
  stem: string;
  options: string[];
}

interface AnswerResult {
  correct?: boolean;
  isCorrect?: boolean;
  correctIndex: number;
  rationale: string;
}

interface ExamHostProps {
  topic?: string;
  files?: string[];
  count?: number;
  difficulty?: string;
  model?: string;
  provider?: string;
  onDismiss: () => void;
}

const API_BASE = '/api/exam';

export function ExamHost(props: ExamHostProps) {
  const {
    onDismiss,
  } = props;
  // Stable defaults — default param values like `files = []` would allocate
  // a fresh array on every render and re-fire the bootstrap useEffect,
  // overwriting the user's current question after every answer/next click.
  const [topic] = useState<string>(() => props.topic ?? 'general knowledge');
  const [files] = useState<string[]>(() => props.files ?? []);
  const [count] = useState<number>(() => props.count ?? 5);
  const [difficulty] = useState<string>(() => props.difficulty ?? 'medium');
  const [sessionModel] = useState<string>(() => props.model ?? '');
  const [sessionProvider] = useState<string>(() => props.provider ?? '');

  const [examId, setExamId] = useState<number | null>(null);
  const [question, setQuestion] = useState<Question | null>(null);
  const [position, setPosition] = useState<number>(1);
  const [totalQuestions, setTotal] = useState<number>(0);
  const [error, setError] = useState<string | null>(null);
  const [loading, setLoading] = useState<boolean>(true);

  // Bootstrap: generate the exam. Run exactly once on mount.
  // topic/files/count/difficulty are now state (stable references), so
  // the deps array never changes after first render.
  useEffect(() => {
    let cancelled = false;
    const bootstrap = async () => {
      try {
        const body: Record<string, unknown> = { count, difficulty };
        if (sessionModel) body.model = sessionModel;
        if (sessionProvider) body.provider = sessionProvider;
        if (files.length > 0) body.files = files;
        else body.topic = topic;

        const resp = await fetch(`${API_BASE}/generate`, {
          method: 'POST',
          headers: { 'Content-Type': 'application/json' },
          body: JSON.stringify(body),
        });
        if (!resp.ok) {
          const err = await resp.json().catch(() => ({} as Record<string, unknown>));
          throw new Error((err as Record<string, unknown>).detail as string || `HTTP ${resp.status}`);
        }
        const data = await resp.json() as { examId?: number; totalQuestions?: number; question?: Question; id?: number; stem?: string; options?: string[]; position?: number };
        if (cancelled) return;
        // Wire format: camelCase (`examId`, `totalQuestions`, …).
        const examIdNum: number | null = data.examId ?? null;
        const total: number = data.totalQuestions ?? 0;
        const rawQ = data.question ?? data;
        const question: Question = {
          id: (rawQ as Question).id,
          examId: (rawQ as Question).examId ?? examIdNum ?? 0,
          position: (rawQ as Question).position ?? 1,
          stem: (rawQ as Question).stem,
          options: (rawQ as Question).options ?? [],
        };
        setExamId(examIdNum);
        setQuestion(question);
        setTotal(total);
        setPosition(1);
      } catch (e) {
        if (!cancelled) setError((e as Error).message);
      } finally {
        if (!cancelled) setLoading(false);
      }
    };
    void bootstrap();
    return () => {
      cancelled = true;
    };
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, []);

  const handleAnswer = useCallback(
    async (questionId: number, selectedIndex: number): Promise<AnswerResult> => {
      if (!examId) throw new Error('No exam');
      const resp = await fetch(`${API_BASE}/${examId}/answer`, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ questionId: questionId, selectedIndex: selectedIndex }),
      });
      if (!resp.ok) throw new Error(`HTTP ${resp.status}`);
      const data = await resp.json();
      // Wire format: camelCase (`isCorrect`, `correctIndex`, `rationale`).
      return {
        isCorrect: data.isCorrect ?? data.correct ?? false,
        correctIndex: data.correctIndex ?? -1,
        rationale: data.rationale ?? '',
      };
    },
    [examId],
  );

  const handleNext = useCallback(async () => {
    if (!examId) return;
    const nextPos = position + 1;
    if (totalQuestions > 0 && nextPos > totalQuestions) {
      // Exam complete — dismiss
      onDismiss();
      return;
    }
    setPosition(nextPos);
    try {
      const resp = await fetch(`${API_BASE}/${examId}/question/${nextPos}`);
      if (!resp.ok) {
        if (resp.status === 404) {
          onDismiss();
          return;
        }
        throw new Error(`HTTP ${resp.status}`);
      }
      const q = await resp.json();
      // Wire format: camelCase (`examId`, `position`, `stem`, `options`).
      const nextQuestion: Question = {
        id: q.id,
        examId: q.examId ?? examId,
        position: q.position ?? nextPos,
        stem: q.stem,
        options: q.options ?? [],
      };
      setQuestion(nextQuestion);
    } catch (e) {
      setError((e as Error).message);
    }
  }, [examId, position, totalQuestions, onDismiss]);

  const handleAddQuestion = useCallback(
    async (request: string) => {
      if (!examId) return;
      const body: Record<string, unknown> = { request };
      if (sessionModel) body.model = sessionModel;
      if (sessionProvider) body.provider = sessionProvider;
      const resp = await fetch(`${API_BASE}/${examId}/questions`, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify(body),
      });
      if (!resp.ok) throw new Error(`HTTP ${resp.status}`);
      const data = await resp.json();
      if (data?.question) {
        setQuestion(data.question);
        setPosition(data.position);
        setTotal((t) => (t > 0 ? t + 1 : t));
      }
    },
    [examId, sessionModel, sessionProvider],
  );

  if (loading) {
    return (
      <div className="fixed bottom-0 left-0 right-0 z-50 border-t border-border bg-card shadow-2xl p-4">
        <div className="mx-auto max-w-3xl text-sm text-muted-foreground">Generating exam…</div>
      </div>
    );
  }
  if (error) {
    return (
      <div className="fixed bottom-0 left-0 right-0 z-50 border-t border-border bg-card shadow-2xl p-4">
        <div className="mx-auto max-w-3xl text-sm text-danger">
          Failed to load exam: {error}
          <button onClick={onDismiss} className="ml-3 underline text-xs">
            dismiss
          </button>
        </div>
      </div>
    );
  }
  if (!question || !examId) return null;

  return (
    <ExamBanner
      key={question.id}
      examId={examId}
      question={question}
      onAnswer={handleAnswer}
      onNext={() => { void handleNext(); }}
      onAddQuestion={handleAddQuestion}
      onDismiss={onDismiss}
    />
  );
}

import { useState } from 'react';
import { useQuery } from '@tanstack/react-query';
import { SectionHeader } from '@/components/SectionHeader';
import { Card, CardContent } from '@/components/ui/card';
import { StatusPill } from '@/components/StatusPill';
import { RightRail } from '@/components/shell/RightRail';
import { PageLoader } from '@/components/PageLoader';
import { formatTimeAgo } from '@/lib/utils';
import {
  getRequestDetails,
  getRequestDetail,
  type RequestDetailEntry,
  type Period,
} from '@/api/api-client';

const PERIODS: { key: Period; label: string }[] = [
  { key: 'today', label: 'Today' },
  { key: 'yesterday', label: 'Yesterday' },
  { key: 'week', label: '7d' },
  { key: 'all', label: 'All' },
];

export function Inspector() {
  const [period, setPeriod] = useState<Period>('today');
  const [selectedId, setSelectedId] = useState<string | null>(null);

  const { data: details, isLoading } = useQuery({
    queryKey: ['request-details', period],
    queryFn: () => getRequestDetails(period),
    refetchInterval: 3_000,
  });

  const { data: selectedDetail } = useQuery({
    queryKey: ['request-detail', selectedId],
    queryFn: () => (selectedId ? getRequestDetail(selectedId) : Promise.resolve(null)),
    enabled: !!selectedId,
  });

  const rows = details ?? [];
  const selected = selectedDetail ?? rows.find((d) => d.reqId === selectedId) ?? null;

  if (isLoading) return <PageLoader label="Loading inspector…" />;

  return (
    <div className="flex h-full">
      <div className="flex-1 flex flex-col min-w-0">
        <div className="p-6 pb-3">
          <SectionHeader
            title="Inspector"
            subtitle={`${rows.length} captured requests · click a row for sanitized bodies`}
            actions={
              <div className="flex items-center gap-1 text-[10px]">
                {PERIODS.map((p) => (
                  <button
                    key={p.key}
                    onClick={() => setPeriod(p.key)}
                    className={`rounded-md px-2 py-1 font-mono transition ${
                      period === p.key ? 'bg-primary text-primary-foreground' : 'text-muted-foreground hover:bg-accent'
                    }`}
                  >
                    {p.label}
                  </button>
                ))}
              </div>
            }
          />
        </div>
        <div className="flex-1 overflow-auto px-6 pb-3 space-y-1.5">
          {rows.length === 0 ? (
            <div className="h-full grid place-items-center text-xs text-muted-foreground">
              No captured requests in this period. Send a chat message to populate the inspector.
            </div>
          ) : (
            rows.slice(0, 120).map((d) => (
              <button
                key={d.reqId}
                onClick={() => setSelectedId(d.reqId)}
                className={`w-full text-left rounded-md border border-border bg-card hover:bg-accent/30 transition px-3 py-2 ${
                  selected?.reqId === d.reqId ? 'ring-1 ring-primary' : ''
                }`}
              >
                <div className="flex items-center gap-3 text-xs font-mono">
                  <DetailStatus status={d.status} error={d.error} />
                  <span className="text-muted-foreground">{d.requestType || 'request'}</span>
                  <span className="font-semibold flex-1 truncate">{d.reqId}</span>
                  {d.date && (
                    <span className="text-muted-foreground text-[10px]">{formatTimeAgo(d.date)}</span>
                  )}
                </div>
              </button>
            ))
          )}
        </div>
      </div>

      {selected && (
        <RightRail title="Request detail" subtitle={selected.reqId}>
          <RequestDetail d={selected} />
        </RightRail>
      )}
    </div>
  );
}

function DetailStatus({ status, error }: { status?: string; error?: string | null }) {
  const isError = status === 'error' || !!error;
  return (
    <StatusPill
      tone={isError ? 'bad' : status === 'completed' ? 'good' : 'muted'}
      label={(status || 'unknown').slice(0, 10)}
    />
  );
}

function RequestDetail({ d }: { d: RequestDetailEntry }) {
  const reqBody = safeStringify(d.requestBody);
  const resBody = safeStringify(d.responseBody);

  return (
    <div className="space-y-3 text-xs">
      <div className="grid grid-cols-2 gap-2">
        <Field label="Status" value={<DetailStatus status={d.status} error={d.error} />} />
        <Field label="Type" value={<span className="font-mono">{d.requestType || '—'}</span>} />
        {d.date && <Field label="Time" value={<span className="font-mono">{new Date(d.date).toLocaleString()}</span>} />}
        {d.finishReason && <Field label="Finish" value={<span className="font-mono">{d.finishReason}</span>} />}
        <Field label="Input tok" value={<span className="font-mono tabular-nums">{(d.inputTokens || 0).toLocaleString()}</span>} />
        <Field label="Output tok" value={<span className="font-mono tabular-nums">{(d.outputTokens || 0).toLocaleString()}</span>} />
      </div>

      {d.error && (
        <Card>
          <CardContent className="p-3">
            <p className="text-[10px] uppercase tracking-wider text-destructive mb-1">Error</p>
            <pre className="text-[10px] font-mono whitespace-pre-wrap break-all bg-destructive/5 text-destructive p-2 rounded">
              {d.error}
            </pre>
          </CardContent>
        </Card>
      )}

      <Card>
        <CardContent className="p-3">
          <p className="text-[10px] uppercase tracking-wider text-muted-foreground mb-2">Request body</p>
          {reqBody ? (
            <pre className="text-[10px] font-mono whitespace-pre-wrap break-all bg-muted p-2 rounded">
              {reqBody}
            </pre>
          ) : (
            <p className="text-[10px] text-muted-foreground italic">Not captured</p>
          )}
        </CardContent>
      </Card>

      <Card>
        <CardContent className="p-3">
          <p className="text-[10px] uppercase tracking-wider text-muted-foreground mb-2">Response body</p>
          {resBody ? (
            <pre className="text-[10px] font-mono whitespace-pre-wrap break-all bg-muted p-2 rounded">
              {resBody}
            </pre>
          ) : (
            <p className="text-[10px] text-muted-foreground italic">Pending or not captured</p>
          )}
        </CardContent>
      </Card>

      {d.thinking != null && (
        <Card>
          <CardContent className="p-3">
            <p className="text-[10px] uppercase tracking-wider text-muted-foreground mb-2">Thinking</p>
            <pre className="text-[10px] font-mono whitespace-pre-wrap break-all bg-muted p-2 rounded">
              {safeStringify(d.thinking)}
            </pre>
          </CardContent>
        </Card>
      )}

      {d.toolCalls != null && (
        <Card>
          <CardContent className="p-3">
            <p className="text-[10px] uppercase tracking-wider text-muted-foreground mb-2">Tool calls</p>
            <pre className="text-[10px] font-mono whitespace-pre-wrap break-all bg-muted p-2 rounded">
              {safeStringify(d.toolCalls)}
            </pre>
          </CardContent>
        </Card>
      )}

      <p className="text-[9px] text-muted-foreground font-mono px-1">
        🔒 Secrets are redacted server-side before display.
      </p>
    </div>
  );
}

function Field({ label, value }: { label: string; value: React.ReactNode }) {
  return (
    <div>
      <p className="text-[10px] uppercase tracking-wider text-muted-foreground">{label}</p>
      <div className="mt-0.5">{value}</div>
    </div>
  );
}

/** Stringify a possibly-object/already-string value, never throwing. */
function safeStringify(v: unknown): string {
  if (v == null || v === '') return '';
  if (typeof v === 'string') {
    // Already-stringified (e.g. sanitizeForDisplay output); pretty-print if JSON.
    try {
      const parsed = JSON.parse(v);
      return JSON.stringify(parsed, null, 2);
    } catch {
      return v;
    }
  }
  try {
    return JSON.stringify(v, null, 2);
  } catch {
    try {
      return JSON.stringify(v);
    } catch {
      return '{}';
    }
  }
}

import { useMemo, useState } from 'react';
import { useQuery } from '@tanstack/react-query';
import { SectionHeader } from '@/components/SectionHeader';
import { Card } from '@/components/ui/card';
import { Badge } from '@/components/ui/badge';
import { StatusPill } from '@/components/StatusPill';
import { Search, Copy, Check } from 'lucide-react';
import { formatTimeAgo } from '@/lib/utils';
import { getRequests, getActivity, type ActivityEntry, type Period } from '@/api/api-client';

/**
 * Logs view. There is no dedicated /ui/logs endpoint, so we compose the log
 * stream from the two real sources the backend exposes:
 *   - /ui/activity  → human activity events (type + detail + time)
 *   - /ui/requests  → request lifecycle entries (status, error, tokens, cost)
 * These are merged into a single chronological feed and filtered by level.
 */

type LogLevel = 'info' | 'warn' | 'error';

interface LogLine {
  id: string;
  time: string;
  level: LogLevel;
  source: 'activity' | 'request' | 'pending';
  message: string;
  raw?: unknown;
}

function levelFromEntry(a: ActivityEntry): LogLevel {
  const t = (a.type || '').toLowerCase();
  if (t.includes('error') || t.includes('fail')) return 'error';
  if (t.includes('warn') || t.includes('pending')) return 'warn';
  return 'info';
}

const PERIODS: { key: Period; label: string }[] = [
  { key: 'today', label: 'Today' },
  { key: 'yesterday', label: 'Yesterday' },
  { key: 'week', label: '7d' },
  { key: 'all', label: 'All' },
];

const LEVEL_FILTERS: { key: 'all' | LogLevel; label: string }[] = [
  { key: 'all', label: 'All' },
  { key: 'info', label: 'Info' },
  { key: 'warn', label: 'Warn' },
  { key: 'error', label: 'Error' },
];

export function Logs() {
  const [period, setPeriod] = useState<Period>('today');
  const [levelFilter, setLevelFilter] = useState<'all' | LogLevel>('all');
  const [filter, setFilter] = useState('');
  const [copied, setCopied] = useState<string | null>(null);

  const { data: reqData } = useQuery({
    queryKey: ['requests', period],
    queryFn: () => getRequests(period),
    refetchInterval: 4_000,
  });
  const { data: activity } = useQuery({
    queryKey: ['activity'],
    queryFn: () => getActivity(),
    refetchInterval: 4_000,
  });

  const lines = useMemo<LogLine[]>(() => {
    const out: LogLine[] = [];
    for (const a of activity ?? []) {
      out.push({
        id: `act-${a.time}-${a.type}`,
        time: a.time,
        level: levelFromEntry(a),
        source: 'activity',
        message: a.detail || a.type,
        raw: a,
      });
    }
    for (const p of reqData?.pending ?? []) {
      out.push({
        id: `pend-${p.reqId}`,
        time: new Date(Date.now() - p.elapsedMs).toISOString(),
        level: 'warn',
        source: 'pending',
        message: `[pending ${p.reqId}] ${p.clientType} ${p.endpoint} (${p.model})`,
        raw: p,
      });
    }
    for (const r of reqData?.completed ?? []) {
      const isError = r.status === 'error';
      out.push({
        id: `req-${r.reqId}`,
        time: r.date || r.time || new Date().toISOString(),
        level: isError ? 'error' : 'info',
        source: 'request',
        message: `[${r.reqId}] ${r.clientType} ${r.endpoint} → ${r.status} (${r.durationMs}ms${r.error ? `, ${r.error}` : ''})`,
        raw: r,
      });
    }
    return out.sort((a, b) => b.time.localeCompare(a.time));
  }, [activity, reqData]);

  const visible = lines.filter((l) => {
    if (levelFilter !== 'all' && l.level !== levelFilter) return false;
    if (filter && !l.message.toLowerCase().includes(filter.toLowerCase())) return false;
    return true;
  });

  const counts = {
    error: lines.filter((l) => l.level === 'error').length,
    warn: lines.filter((l) => l.level === 'warn').length,
    info: lines.filter((l) => l.level === 'info').length,
  };

  function copyLine(l: LogLine) {
    const safe = JSON.stringify(l.raw, (k, v) => {
      // Never copy secret-shaped fields.
      if (/key|token|secret|password|authorization|cookie/i.test(k)) return '[REDACTED]';
      return v;
    }, 2);
    void navigator.clipboard?.writeText(safe);
    setCopied(l.id);
    setTimeout(() => setCopied(null), 1200);
  }

  return (
    <div className="flex flex-col h-full p-6 gap-4">
      <SectionHeader
        title="Logs"
        subtitle={`${lines.length} entries · ${counts.error} errors · ${counts.warn} warnings`}
        actions={
          <div className="flex items-center gap-2">
            <div className="flex items-center gap-1 text-[10px]">
              {LEVEL_FILTERS.map((f) => (
                <button
                  key={f.key}
                  onClick={() => setLevelFilter(f.key)}
                  className={`rounded-md px-2 py-1 font-mono transition ${
                    levelFilter === f.key ? 'bg-primary text-primary-foreground' : 'text-muted-foreground hover:bg-accent'
                  }`}
                >
                  {f.label}
                </button>
              ))}
            </div>
            <div className="flex items-center gap-1 text-[10px]">
              {PERIODS.map((p) => (
                <button
                  key={p.key}
                  onClick={() => setPeriod(p.key)}
                  className={`rounded-md px-2 py-1 font-mono transition ${
                    period === p.key ? 'bg-primary text-primary-foreground' : 'text-muted-foreground hover:bg-accent'
                  }`}
                >
                  {p.label}
                </button>
              ))}
            </div>
          </div>
        }
      />

      <div className="relative max-w-md">
        <Search className="absolute left-2 top-1/2 -translate-y-1/2 size-3.5 text-muted-foreground" />
        <input
          value={filter}
          onChange={(e) => setFilter(e.target.value)}
          placeholder="Filter logs…"
          className="w-full pl-7 pr-2 py-1.5 text-xs bg-secondary rounded-md border border-transparent focus:border-border focus:bg-background outline-none transition"
        />
      </div>

      <Card className="flex-1 overflow-auto min-h-[260px]">
        <div className="font-mono text-[11px] divide-y divide-border/40">
          {visible.length === 0 ? (
            <div className="p-6 text-center text-muted-foreground">No log entries match the current filter.</div>
          ) : (
            visible.map((l) => (
              <div key={l.id} className="flex items-start gap-2 px-3 py-1.5 hover:bg-accent/20 group">
                <span className="text-muted-foreground/70 shrink-0 w-28">{formatTimeAgo(l.time)}</span>
                <span className="shrink-0 w-16">
                  <LevelBadge level={l.level} />
                </span>
                <span className="shrink-0 w-16 text-muted-foreground">{l.source}</span>
                <span className="flex-1 break-all whitespace-pre-wrap">{l.message}</span>
                <button
                  onClick={() => copyLine(l)}
                  className="opacity-0 group-hover:opacity-100 text-muted-foreground hover:text-foreground transition shrink-0"
                  title="Copy redacted entry"
                >
                  {copied === l.id ? <Check className="size-3" /> : <Copy className="size-3" />}
                </button>
              </div>
            ))
          )}
        </div>
      </Card>
      <p className="text-[9px] text-muted-foreground font-mono">
        🔒 Secret-shaped fields (keys, tokens, cookies) are redacted on copy. Pending requests surface as warnings.
      </p>
    </div>
  );
}

function LevelBadge({ level }: { level: LogLevel }) {
  if (level === 'error') return <StatusPill tone="bad" label="error" />;
  if (level === 'warn') return <Badge variant="outline" className="border-warning/50 text-warning">{level}</Badge>;
  return <Badge variant="outline">{level}</Badge>;
}

