/* ── useConversationInspector — shared data layer for the merged
 *   Conversation Inspector section ──────────────────────────────────
 * The old Inspector/Conversations/Thinking components each fetched their
 * own slice of /ui/details + /ui/conversations independently — and the old
 * Inspector also issued an extra /ui/detail/:reqId call when a row was
 * selected, even though the same data was already in the list response.
 *
 * This hook fetches /ui/details + /ui/conversations once for the chosen
 * period, exposes the unified row list, the selected request, a normalized
 * transcript for the Readable tab, and an extracted thinking-traces list
 * for the Thinking tab. The three old sub-sections now read from one
 * poll cycle and share a single selected-request state. */

import { useMemo } from 'react';
import { useQuery } from '@tanstack/react-query';
import {
  getRequestDetails,
  getConversations,
  type RequestDetailEntry,
  type ConversationsResponse,
  type Period,
  type RequestEntry,
} from '@/api/api-client';

export interface MessageItem {
  role: string;
  content: string;
}

export interface ConversationItem {
  reqId: string;
  clientType: string;
  model: string;
  status: string;
  date?: string;
  messages: MessageItem[];
  response?: unknown;
  finishReason?: string | null;
  error?: string | null;
}

export interface ThinkingTrace {
  reqId: string;
  date?: string;
  thinking: string;
  finishReason?: string | null;
}

export interface InspectorRow {
  reqId: string;
  clientType: string;
  model: string;
  status: string;
  date?: string;
  requestType?: string;
  /** True if the captured detail includes any non-empty thinking trace. */
  hasThinking: boolean;
  /** True if the detail is in an error state. */
  isError: boolean;
}

function toMessages(raw: unknown): MessageItem[] {
  if (!Array.isArray(raw)) return [];
  return raw
    .map((m: unknown) => {
      const msg = m as { role?: string; content?: string | Array<unknown> | { text?: string; content?: string } };
      const role = msg?.role || 'unknown';
      let content = '';
      if (typeof msg?.content === 'string') content = msg.content;
      else if (Array.isArray(msg?.content)) {
        content = msg.content
          .map((b: unknown) => {
            const block = b as { text?: string; content?: string; type?: string };
            return typeof b === 'string' ? b : block?.text || block?.content || block?.type || '';
          })
          .filter(Boolean)
          .join('\n');
      } else if (msg?.content && typeof msg.content === 'object') {
        const textVal = msg.content.text || msg.content.content || '';
        content = typeof textVal === 'string' ? textVal : JSON.stringify(textVal);
      }
      return { role, content };
    })
    .filter((m) => m.content);
}

function normalizeConversations(grouped: ConversationsResponse | undefined): ConversationItem[] {
  const items: ConversationItem[] = [];
  for (const [clientType, entries] of Object.entries(grouped || {})) {
    for (const e of entries as Array<RequestEntry & {
      details: { messages: unknown; response: unknown; finishReason?: string | null; error?: string | null } | null;
    }>) {
      items.push({
        reqId: e.reqId,
        clientType,
        model: e.model || 'unknown',
        status: e.status || 'unknown',
        date: e.date,
        messages: toMessages(e.details?.messages),
        response: e.details?.response,
        finishReason: e.details?.finishReason,
        error: e.details?.error,
      });
    }
  }
  return items.sort((a, b) => (b.date || '').localeCompare(a.date || ''));
}

function stringifyThinking(v: unknown): string {
  if (v == null) return '';
  if (typeof v === 'string') return v;
  try {
    if (Array.isArray(v)) {
      // Anthropic thinking blocks: [{ type: 'thinking', thinking: '...' }]
      return v
        .map((b: unknown) => (typeof b === 'string' ? b : (b as { thinking?: string; text?: string })?.thinking || (b as { thinking?: string; text?: string })?.text || ''))
        .filter(Boolean)
        .join('\n');
    }
    if (typeof v === 'object') {
      const o = v as Record<string, unknown>;
      const textVal = o.thinking || o.text || o.content || '';
      return typeof textVal === 'string' ? textVal : JSON.stringify(textVal);
    }
  } catch { /* ignore */ }
  return typeof v === 'string' ? v : JSON.stringify(v);
}

function extractTraces(details: RequestDetailEntry[] | undefined): ThinkingTrace[] {
  if (!details) return [];
  const traces: ThinkingTrace[] = [];
  for (const d of details) {
    const text = stringifyThinking(d.thinking);
    if (!text || !text.trim()) continue;
    traces.push({ reqId: d.reqId, date: d.date, thinking: text, finishReason: d.finishReason });
  }
  return traces;
}

/** Safe JSON pretty-printer that never throws and pretty-prints JSON strings. */
function safeStringify(v: unknown): string {
  if (v == null || v === '') return '';
  if (typeof v === 'string') {
    try {
      const parsed = JSON.parse(v);
      return JSON.stringify(parsed, null, 2);
    } catch {
      return v;
    }
  }
  try {
    return JSON.stringify(v, null, 2);
  } catch {
    try {
      return JSON.stringify(v);
    } catch {
      return '{}';
    }
  }
}

export function useConversationInspector(period: Period) {
  const detailsQuery = useQuery({
    queryKey: ['ci-details', period],
    queryFn: () => getRequestDetails(period),
    refetchInterval: 3_000,
  });
  const conversationsQuery = useQuery({
    queryKey: ['ci-conversations', period],
    queryFn: () => getConversations(period),
    refetchInterval: 5_000,
  });

  const details = useMemo(() => detailsQuery.data ?? [], [detailsQuery.data]);
  const conversations = useMemo(() => normalizeConversations(conversationsQuery.data), [conversationsQuery.data]);
  const thinking = useMemo(() => extractTraces(details), [details]);

  /** Unified row list: every request that has either detail or a transcript. */
  const rows = useMemo<InspectorRow[]>(() => {
    const byReq = new Map<string, InspectorRow>();
    for (const d of details) {
      byReq.set(d.reqId, {
        reqId: d.reqId,
        clientType: 'unknown',
        model: 'unknown',
        status: d.status || 'unknown',
        date: d.date,
        requestType: d.requestType,
        hasThinking: !!stringifyThinking(d.thinking).trim(),
        isError: d.status === 'error' || !!d.error,
      });
    }
    for (const c of conversations) {
      const existing = byReq.get(c.reqId);
      if (existing) {
        existing.clientType = c.clientType;
        existing.model = c.model;
      } else {
        byReq.set(c.reqId, {
          reqId: c.reqId,
          clientType: c.clientType,
          model: c.model,
          status: c.status,
          date: c.date,
          hasThinking: false,
          isError: c.status === 'error' || !!c.error,
        });
      }
    }
    return Array.from(byReq.values()).sort((a, b) => (b.date || '').localeCompare(a.date || ''));
  }, [details, conversations]);

  return {
    rows,
    details,
    conversations,
    thinking,
    isLoading: detailsQuery.isLoading && conversationsQuery.isLoading,
    /** Find the selected detail, conversation, and trace by reqId. */
    select: (reqId: string | null) => {
      const detail = reqId ? details.find((d) => d.reqId === reqId) ?? null : null;
      const conversation = reqId ? conversations.find((c) => c.reqId === reqId) ?? null : null;
      const trace = reqId ? thinking.find((t) => t.reqId === reqId) ?? null : null;
      return { detail, conversation, trace };
    },
    safeStringify,
  };
}

/* ── useTrafficActivity — shared data layer for Traffic & Activity ──── */
/* The old Overview/Traffic/Usage/Logs sections each polled /ui/requests,
 * /ui/stats, /ui/activity, and /api/usage/* independently — up to 4x the
 * network calls for the same data. This hook fetches each source once and
 * exposes normalized rows + stats + a merged log feed so every tab in the
 * section reads from one poll cycle. */

import { useMemo } from 'react';
import { useQuery } from '@tanstack/react-query';
import {
  getRequests,
  getStats,
  getActivity,
  type RequestEntry,
  type PendingRequest,
  type ActivityEntry,
  type StatsResponse,
} from '@/api/api-client';

export type Period = 'all' | 'today' | 'yesterday' | 'week' | 'month' | 'year';
export type StatusFilter = 'all' | 'ok' | 'err';

/** Normalized row so renderers stay mock-shape-agnostic. */
export interface TrafficRow {
  reqId: string;
  clientType: string;
  endpoint: string;
  model: string;
  status: string;
  durationMs: number;
  inputTokens: number;
  outputTokens: number;
  totalCost: number;
  timestamp: number | string;
  error?: string | null;
}

function toRow(r: RequestEntry): TrafficRow {
  return {
    reqId: r.reqId,
    clientType: r.clientType || 'unknown',
    endpoint: r.endpoint || '',
    model: r.model || 'unknown',
    status: r.status || 'unknown',
    durationMs: r.durationMs || 0,
    inputTokens: r.inputTokens || 0,
    outputTokens: r.outputTokens || 0,
    totalCost: r.totalCost || 0,
    timestamp: r.timestamp || r.date || r.time || Date.now(),
    error: r.error,
  };
}

export type LogLevel = 'info' | 'warn' | 'error';

export interface LogLine {
  id: string;
  time: string;
  level: LogLevel;
  source: 'activity' | 'request' | 'pending';
  message: string;
  raw?: unknown;
}

function levelFromEntry(a: ActivityEntry): LogLevel {
  const t = (a.type || '').toLowerCase();
  if (t.includes('error') || t.includes('fail')) return 'error';
  if (t.includes('warn') || t.includes('pending')) return 'warn';
  return 'info';
}

export interface TrafficActivityData {
  rows: TrafficRow[];
  pending: PendingRequest[];
  stats: StatsResponse | undefined;
  activity: ActivityEntry[];
  lines: LogLine[];
  counts: { info: number; warn: number; error: number };
  isLoading: boolean;
}

export function useTrafficActivity(period: Period) {
  const reqQuery = useQuery({
    queryKey: ['ta-requests', period],
    queryFn: () => getRequests(period),
    refetchInterval: 3_000,
  });
  const statsQuery = useQuery({
    queryKey: ['ta-stats', period],
    queryFn: () => getStats(period),
    refetchInterval: 5_000,
  });
  const activityQuery = useQuery({
    queryKey: ['ta-activity'],
    queryFn: () => getActivity(),
    refetchInterval: 5_000,
  });

  // ── Defensive normalization ──────────────────────────────────────
  // The backend may return a 404, an error envelope ({ error, ... }), or a
  // wrapper object ({ entries: [...] }) instead of the bare array/shape the
  // UI expects. `?? []` only guards null/undefined — a truthy object would
  // reach the `for...of` below and throw "activity is not iterable", crashing
  // the whole Observability section (black screen). Coerce every source to a
  // real array before any iteration.
  const asArray = <T,>(v: unknown): T[] => (Array.isArray(v) ? v : []);

  const reqData = reqQuery.data as { pending?: unknown; completed?: unknown } | undefined;
  const pending = asArray<PendingRequest>(reqData?.pending);
  const rows = useMemo(() => asArray<RequestEntry>(reqData?.completed).map(toRow), [reqData?.completed]);
  const activity = asArray<ActivityEntry>(activityQuery.data);
  const stats = statsQuery.data;

  const lines = useMemo<LogLine[]>(() => {
    const out: LogLine[] = [];
    for (const a of activity) {
      out.push({
        id: `act-${a.time}-${a.type}`,
        time: a.time,
        level: levelFromEntry(a),
        source: 'activity',
        message: a.detail || a.type,
        raw: a,
      });
    }
    for (const p of pending) {
      out.push({
        id: `pend-${p.reqId}`,
        time: new Date(Date.now() - p.elapsedMs).toISOString(),
        level: 'warn',
        source: 'pending',
        message: `[pending ${p.reqId}] ${p.clientType} ${p.endpoint} (${p.model})`,
        raw: p,
      });
    }
    for (const r of rows) {
      const isError = r.status === 'error';
      out.push({
        id: `req-${r.reqId}`,
        time: String(r.timestamp),
        level: isError ? 'error' : 'info',
        source: 'request',
        message: `[${r.reqId}] ${r.clientType} ${r.endpoint} → ${r.status} (${r.durationMs}ms${r.error ? `, ${r.error}` : ''})`,
        raw: r,
      });
    }
    return out.sort((a, b) => b.time.localeCompare(a.time));
  }, [activity, pending, rows]);

  const counts = useMemo(
    () => ({
      error: lines.filter((l) => l.level === 'error').length,
      warn: lines.filter((l) => l.level === 'warn').length,
      info: lines.filter((l) => l.level === 'info').length,
    }),
    [lines],
  );

  return {
    rows,
    pending,
    stats,
    activity,
    lines,
    counts,
    isLoading: reqQuery.isLoading && statsQuery.isLoading,
  };
}

export function applyStatusFilter(rows: TrafficRow[], filter: StatusFilter): TrafficRow[] {
  if (filter === 'all') return rows;
  if (filter === 'err') return rows.filter((r) => r.status === 'error');
  return rows.filter((r) => r.status !== 'error');
}

/* ── WorkspaceModelsSection — full Model settings CRUD ───────────────── */
/* Three subtabs in a top-level tab strip:
 *   • Providers — the existing two-column CRUD (left rail + per-provider
 *     editor) — every entry on the left comes from /api/providers. Shows
 *     a one-time "restart backend" hint when the list is empty so users
 *     discover that the built-in registry seed runs on backend startup.
 *   • Aliases — user-defined model aliases that route to a real model
 *     + provider. Replaces the lost "user-aliases" tab from the old
 *     Models.tsx. Stored in config.json via /api/config/model-aliases.
 *   • Quotas — per-model daily token usage. Uses QuotasPanel (lifted
